(window.courseContentFiles = window.courseContentFiles || {})["000003/0006"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1><span style=\"color: rgb(88, 129, 87); font-weight: 600; text-align: center\"></span></h1><h1 style=\"text-align: center\">Тема 3. Възпалителни заболявания на дихателните пътища – бронхит, бронхиолит.</h1><h1>Остър трахеит, бронхит и бронхиолит</h1><h3>Определение и етиология</h3><p>Възникването на острия възпалителен процес на трахеята (tracheitis), на бронхите (bronchitis) и бронхиолите (bronchiolitis) най-често се причинява от вируси и бактерии като стрептококи, стафилококи, пневмококи, Haemophilus influenzae и др. Благоприятстващи условия са простудата, вдишването на запрашен въздух и дразнещи химически вещества.</p><h3>Морфогенеза</h3><p>Възможни са два механизма: инфектиране от окръжаващата среда или автоинфекция (активиране на флората от назофаринкса). Тези състояния могат да бъдат и вторични като усложнение на грип, пертусис, морбили, пневмония, след интубация или механична вентилация.</p><h3>Остър трахеит</h3><p>Наблюдава се най-често като катарален и слузно-гноен. По-рядко се срещат фибринозен и хеморагичен вариант, типични за дифтерия, грип или травма след интубация.</p><h3>Остър бронхит</h3><p>Представлява възпалените на <strong>извънлобуларните </strong>въздухоносни пътища. Според дълбочината на засягане бива:</p><ul><li><strong>Ендoбронхит:</strong> само лигавицата.</li><li><strong>Ендо-мезобронхит:</strong> лигавицата и мускулния слой.</li><li><strong>Панбронхит:</strong> цялата стена (при бронхи от среден и малък калибър).</li><li><strong>Перибронхит:</strong> възпаление на мезенхимната тъкан около бронха.</li></ul><h3>Макроскопски характеристики на острия бронхит</h3><ul><li><strong><span class=\"editor-note\" data-note=\"## bronchitis catarrhalis acuta и bronchitis mucopurulenta acuta\" id=\"note-1776179537038-1\">Катарален и слузно-гноен</span>:</strong> лигавицата е зачервена, набъбнала и покрита със слуз или слузно-гноен ексудат.</li><li><strong><span class=\"editor-note\" data-note=\"## bronchitis fibrinopurulenta acuta\" id=\"note-1776179547061-2\">Фибринозно-гноен</span>:</strong> наличие на сивкаво-жълтеникав ципест налеп (левкоцити и фибрин), който може да се отдели като отливка на бронха.</li><li><strong><span class=\"editor-note\" data-note=\"## bronchitis haemorrhagica acuta\" id=\"note-1776179527639-0\">Хеморагичен</span>:</strong> силна хиперемия, ерозии и кръвенист ексудат.</li><li><strong><span class=\"editor-note\" data-note=\"## bronchitis necroticans acuta\" id=\"note-1776179568893-3\">Некротичен</span>:</strong> най-тежката форма (при <span class=\"editor-note\" data-note=\"Силно дразнещи пари и газове от химични и бойни отровни вещества\" id=\"note-1776179640282-4\">химични изгаряния</span> или <span class=\"editor-note\" data-note=\"Грип, морбили, коклюш\" id=\"note-1776179653083-5\">тежки инфекции</span>). Характеризира се с ерозии, разязвявания и деструкция на всички слоеве на бронхиалната стена до оголване на бронхиалните хрущяли.</li></ul><h3>Микроскопски характеристики на острия бронхит</h3><p>При катаралния вариант лумените са изпълнени със слуз, излющени епителни клетки и единични левкоцити. При слузно-гнойния бронхит количеството на неутрофилите нараства значително и те инфилтрират и субмукозата.</p><h3>Остър бронхиолит</h3><p>Това е възпаление на <strong>интралобуларните </strong>въздухоносни пътища. Често води до тежка диспнея и тахипнея. У кърмачета и стари хора може да доведе до смърт, без забележими клинични прояви.</p><ul><li><strong>Макроскопски:</strong> в лумена се събира катарален или гноен ексудат. При срез на белия дроб той излиза под формата на <strong>сивкавобелезникави запушалки</strong>. Повърхността на дроба показва малки, хлътнали тъмночервени участъци (<strong>огнищни ателектази</strong>) поради обструкцията.</li><li><strong>Микроскопски </strong>- зависи от формата на бронхиолита:</li><ul><li><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183000024-image.png &quot;width=100%&quot;)\" id=\"note-1776183007106-6\">Лимфоцитен бронхиолит</span>.</li><li><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183020380-image.png &quot;width=100%&quot;)\" id=\"note-1776183021917-7\">Фоликуларен бронхиолит</span>.</li><li><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183037844-image.png &quot;width=100%&quot;)\" id=\"note-1776183039652-8\">Цикатрициален (стенозиращ, облитериращ) бронхиолит</span>.</li><li><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183046988-image.png &quot;width=100%&quot;)\" id=\"note-1776183048906-9\">Пролиферативен бронхиолит</span>.</li></ul><li><strong>Изход:</strong> неблагоприятен изход е организацията на ексудата, водеща до <strong>облитериращ бронхиолит</strong>. Често преминава в огнищна пневмония.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен бронхит</h2><h3>Определение</h3><p>Персистираща кашлица с експекторация поне 3 месеца в продължение на 2 години.</p><h3>Етиология</h3><p>Причинява се от бактериални агенти на фона на хронично дразнене (тютюнопушене, прах, студен и влажен въздух). </p><h3>Механизми</h3><p>Основна роля играе нарушената очистително-дренажна функция на бронхите:</p><ul><li>Увреждане на ресничките.</li><li>Директна увреда на респираторния епител.</li><li>Потискане на способността на алвеоларните макрофаги и левкоцити да остранят бактериите.</li><li><p>Промяна в слузната секреция.</p><br></li></ul><h4>Форми:</h4><ul><li><strong>Обикновен хроничен бронхит </strong>- продуктивна кашлица без обструкция.</li><li><strong>Хроничен астматичен бронхит </strong>- периодичен спазъм и хиперергична реакция от страна на бронхите.</li><li><strong>Обструктивен хроничен бронхит </strong>- упорити пушачи - хронична обструкция и емфизем.</li></ul><h3>Макроскопски промени</h3><p>Лигавицата е розово-червена и неравна.</p><ul><li><strong>Хипертрофична форма:</strong> лигавицата и стената са задебелени, а луменът е разширен.</li><li><strong>Атрофична форма:</strong> стената изтънява, става прозрачна и се виждат гънки като „гофрирана тръба“.</li></ul><h3>Микроскопски промени</h3><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183464433-image.png &quot;width=100%&quot;)\" id=\"note-1776183466374-11\">Хиперсекреция на слуз</span>:</strong> дължи се на увеличен брой чашковидни клетки и хиперплазия на бронхиалните жлези (<span class=\"editor-note\" data-note=\"**Reid Index** - Дебелината на жлезния слой/дебелината на стената между епитла и хрущяла = **0.4**\nПри хроничен брохит - индексът е по-висок.\" id=\"note-1776183314239-10\">индекс на Reid</span>).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183473743-image.png &quot;width=100%&quot;)\" id=\"note-1776183475261-12\">Възпаление</span>:</strong> инфилтрат от лимфоцити, плазмоцити и фибробласти в стената.</li><li><strong>Метаплазия:</strong> плоскоклетъчна метаплазия на епитела.</li><li><strong>Склероза:</strong> задебелена и хиалинизирана базална мембрана. Понякога се формират възпалителни полипи от гранулационна тъкан.</li></ul><h3>Усложнения</h3><ul><li>Ателектаза</li><li>Хроничен обструктивен емфизем</li><li>Бронхиектазии</li><li>Бронхиален карцином</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 4. Туморни заболявания на дихателните пътища; назофаринкс, ларинкс.<br></h1><h2>ТУМОРИ НА НАЗОФАРИНКСА</h2><h3>Ювенилен назофарингеален ангиофибром</h3><p>Това е най-характерният представител на доброкачествените тумори с тази локализация. Среща се изключително у момчета преди пубертета и има склонност към обратно развитие в следващите възрастови периоди.</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183888453-image.png &quot;width=100%&quot;)\" id=\"note-1776183890428-13\">Макроскопски</span>:</strong> Изглежда като лобулирана туморна маса с плътна консистенция. Най-често е разположен в сфеноетмоидалния джоб или прониква към носната кухина, предизвиквайки обструкция.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183946807-image.png &quot;width=100%&quot;)\" id=\"note-1776183949183-14\">Микроскопски</span>:</strong> Туморът е съставен от две основни компоненти:</li><ul><li><strong>Съдова компонента:</strong> Дилатирани и разклонени съдове, които често се описват с формата на <strong>\"еленови рога\"</strong>.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776183979717-image.png &quot;width=100%&quot;)\" id=\"note-1776183981433-15\">Фиброматозна компонента</span>:</strong> Сочни фибробласти (източени или полиморфни), разположени сред мрежа от колагенови влакна. Липсват клетъчен атипизъм и неправилни митози.</li></ul><li><strong>Биологично поведение:</strong> Макар и доброкачествен, туморът има <strong>местен деструктивен растеж</strong>. Може да прорастне към черепната кухина и да предизвика увреждане на черепно-мозъчните нерви.</li></ul><h3>Назофарингеален карцином</h3><h4>Честота и Етиология</h4><p>Представлява около 3% от злокачествените тумори при бялата раса и до 15% при азиатци. Засяга по-често мъже (възраст 50-60 г.).</p><ul><li><strong>Етиологични фактори:</strong> Генетична предразположеност, тютюнопушене и хронични възпаления (отити, синуити).</li><li><strong>Вирусна връзка:</strong> Доказана е ролята на <strong>вируса на Ебщайн-Бар (EBV)</strong>. Може да се развие и при пациенти със СПИН.</li></ul><h4>Локализация и разпространение</h4><p>Развива се предимно в страничните стени на назофаринкса. Около <strong>2/3 от болните имат шийни метастази</strong> още при първия преглед. Туморът лесно се разпространява към меките тъкани на шията, ларингеалните нерви и щитовидната жлеза.</p><h4>Диагностика (Биопсично изследване)</h4><p>Биопсията е задължителна, дори при негативен оглед, ако има съмнителни шийни метастази. Прилага се:</p><ol><li>Задна риноскопия с биопсия.</li><li>Тънкоиглена аспирационна биопсия (ТАБ) като алтернатива.</li></ol><h4>Морфология</h4><ul><li><strong>Макроскопски:</strong> Представя се като лобулирана екзофитна маса или като дълбока язва с плътни ръбове (ендофитен растеж).</li><li><strong>Микроскопски варианти:</strong> Хистологично се проявява в три основни форми:</li><ol><li><strong>Вроговяващ плоскоклетъчен карцином.</strong></li><li><strong>Невроговяващ плоскоклетъчен карцином.</strong></li><li><strong>Недиференциран карцином.</strong></li></ol></ul><h4>Особеност (Лимфоепителиом)</h4><p>Недиференцираният вариант често се описва като \"лимфоепителиом\", тъй като туморните клетки са разположени сред обилна лимфоцитна инфилтрация, което понякога затруднява хистологичната диагноза.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>ТУМОРИ НА ЛАРИНКСА</h2><h3>ДОБРОКАЧЕСТВЕНИ ТУМОРИ</h3><h4>Плоскоклетъчен папилом</h4><p>Най-честият доброкачествен тумор в тази област (40-50% при възрастни и почти единствен при деца).</p><ul><li><strong>Макроскопски:</strong> Дребнозърнеста сиво-червеникава маса с размери 3-5 mm.</li><li><strong>Микроскопски:</strong> Строеж на сквамозен папилом, понякога с вроговяване. Различават се спокоен и пролифериращ вариант. В редки случаи промените могат да достигнат до степен на <em>carcinoma in situ</em>.</li></ul><h4>Папилом на детско-юношеската възраст</h4><p>Свързва се с наличието на остри кондиломи у майката по време на бременността. Приема се вирусна етиология - най-често поради <span class=\"editor-note\" data-note=\"# Бонус обща култура\n**Етиология и типове**\n* Причинява се основно от Human papillomavirus типове **6 и 11**\n* Това са **нискорискови (low-risk) типове** → рядко водят до малигнизация\n* Тип **11** обикновено протича **по-агресивно** от тип 6 (повече рецидиви, по-тежко засягане)\n**Начин на предаване**\n* При деца: най-често **вертикално предаване при раждане** (от майка с генитална HPV инфекция)\n* По-рядко – постнатално\n**Локализация и клиника**\n* Най-често засяга **ларинкса (гласните връзки)** → дрезгав глас е първи симптом\n* Може да обхване и цялото респираторно дърво (рядко – белите дробове)\n* Характерно е **рецидивиращо протичане** с нужда от многократни интервенции\n**Онкогенен риск**\n* HPV 6 и 11 **не интегрират ефективно** в генома и не инактивират силно p53/Rb\n* Малигнизация е **рядка**, но възможна при дългогодишно протичане\n**Профилактика**\n* HPV vaccine покрива типове **6 и 11** → намалява риска от заболяването\" id=\"note-1776186396350-17\">HPV 6, 11</span>.</p><ul><li><strong>Морфология:</strong> Никога не малигнизира и често изчезва спонтанно през пубертета.</li><li><strong>Макроскопски:</strong> Проявява се като множествена папиломатоза, която може да обхване целия ларинкс.</li><li><strong>Микроскопски:</strong> <span class=\"editor-note\" data-note=\"Думата „**пищен**“ в този контекст означава:\n- силно развит, обилен, разраснал се (хиперпластичен)\" id=\"note-1776186346298-16\"></span><p>Изразен растеж на многослоен плосък епител с множество митози във всички слоеве. Пролифериралият епител обгражда нежна съединителнотъканна строма с капиляри и оскъдна стромна реакция.</p>.</li></ul><h4>Фибром на ларинкса (Певчески възел, Полип на гласните връзки)</h4><p>Счита се за псевдотуморен или реактивен процес, дължащ се на пренапрежение на гласовия апарат. Среща се предимно у мъже (30-50 г.) и професионални певци.</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776186557585-image.png &quot;width=100%&quot;)\" id=\"note-1776186559728-18\">Макроскопски</span>:</strong> Единичен мековат възел (няколко mm), обикновено на гласните връзки, често на краче и по-рядко на широка основа.</li><li><strong><span class=\"editor-note\" data-note=\"## **Хиперпластичен многослоен плосък епител с лека реактивна цитологична атипия. Подлежащата ламина проприя съдържа разширени (телангиектазични) капиляри и оскъдна съединителнотъканна строма.**\n![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776186703258-image.png &quot;width=100%&quot;)\" id=\"note-1776186713207-19\">Микроскопски</span>:</strong> Фиброзна тъкан, покрита с <strong>вроговяващ </strong>многослоен плосък епител. Характерни са съдове със задебелени, хомогенни стени, пропити с белтъчно вещество (позитивно за амилоид и фибрин). Не рецидивира и не малигнизира.</li></ul><h3>ЗЛОКАЧЕСТВЕНИ ТУМОРИ НА ЛАРИНКСА</h3><h4>Карцином на ларинкса</h4><p>Най-честият злокачествен тумор в областта (99% от неоплазмите на ларинкса). Засяга предимно мъже (10:1) между 50 и 70 години.</p><ul><li><strong>Етиология и преканцерози:</strong> Основен фактор е тютюнопушенето и химическите канцерогени. Преканцерозни състояния: папиломатоза, хроничен ларингит, пахидермия и кератоза на гласните връзки.</li><li><strong>Клиника:</strong> Проявява се с дисфония (дрезгав глас) и затруднено дишане (поради стеноза).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776186837725-image.png &quot;width=100%&quot;)\" id=\"note-1776186839319-20\">Локализация</span>:</strong> </li><ul><li>Глотичен (най-чест): 50-60%.</li><li>Супраглотичен: 20-30%.</li><li>Fossa piriformis и хипофаринкс: 10-20%.</li></ul></ul><h4>Морфологична картина</h4><ul><li><strong>Макроскопски:</strong> Може да бъде единичен възел или мултифокален растеж. Най-често се представя като <strong>язва с плътни подлежащи тъкани</strong>, по-рядко като папиларни разраствания или трошлив възел. Гласните връзки са типична локализация с по-ниска агресивност и по-добра прогноза след оперативно лечение.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776187170328-image.png &quot;width=100%&quot;)\" id=\"note-1776187172128-22\">Микроскопски</span>:</strong></li><ul><li>В 90% от случаите е <strong>плоскоклетъчен карцином </strong>с различна степен на диференциация.</li><li>При високодиференцираните форми се наблюдават характерни <strong>\"<span class=\"editor-note\" data-note=\"![Image](https://cdn.lecturio.com/assets/Keratin_Pearls_in_Squamous_Cell_Carcinoma_of_the_Larynx.jpg &quot;width=60%&quot;)\" id=\"note-1776187144364-21\">ракови перли</span>\"</strong> (вроговяване).</li></ul><li><strong>Биологично поведение:</strong> Инфилтративен растеж в околните тъкани и метастазиране в регионалните лимфни възли.&nbsp;<p>Прог</p><p>нозата му зависи от степента на диференциация и </p><p>стадия на туморния процес.</p></li></ul><h4>Други редки злокачествени тумори</h4><p>В ларинкса и хипофаринкса могат да се срещнат още:</p><ul><li>Невроендокринни тумори.</li><li>Малигнени мекотъканни тумори.</li><li>Хематолимфоидни бластоми.</li><li>Мукозен малигнен меланом.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 5. Пневмонии – класификация. Вирусни пневмонии – морфологична характеристика.</h1><p><strong style=\"color: rgb(31, 41, 55)\">Определение.</strong> Пневмонията е термин, с който се означава възпалението на респираторния отдел в белия дроб, включващо алвеолите, алвеоларните ходове и респираторните бронхиоли.</p><ul><li><strong>Алвеоларна пневмония:</strong> Когато възпалението обхваща горепосочените структури.</li><li><strong>Интерстициална пневмония:</strong> Когато процесът ангажира белодробния интерстициум (междуалвеоларните стени, перибронхиалната, перивазалната и перилобуларната тъкан).</li></ul><h2>Патогенеза и болнични пневмонии</h2><p><strong>Механизми на инфектиране и разпространение:</strong></p><ul><li><strong>Входна врата:</strong> Най-често това е респираторният тракт чрез аспирация или инхалация на патогени.</li><li><strong>Хематогенно разпространение:</strong> Причинява вторични пневмонии, възникващи в резултат на инфекциозно огнище в друг орган.</li><li><strong>Вторична инфекция:</strong> Често се наблюдава преминаване от един тип пневмония в друг – например вирусна инфекция, която уврежда защитните механизми и води до развитие на вторична бактериална пневмония.</li><li><strong><span class=\"editor-note\" data-note=\"## Нозокомиални (вътреболнични) пневмонии\n**Определение:** Нозокомиалната пневмония (HAP) е инфекция на белодробния паренхим, която се развива при пациенти, приети в болница за 48 часа или повече, при условие че симптомите не са били в инкубационен период при постъпването.\n- **Клинична характеристика:** Обикновено инкубационният период е поне 2 дни. Инфекцията се причинява от специфични патогени, които се изолират най-често в болнична среда.\n- **Рискови групи:** Най-застрашени са пациенти с хронични заболявания и отслабен имунитет, които придобиват инфекцията по време на хоспитализацията.\" id=\"note-1776188916316-24\">Нозокомиална инфекция</span>:</strong>&nbsp;Пациенти с хронични заболявания придобиват пневмонии при хоспитализацията.</li></ul><h2>Класификация</h2><p>Многообразието на морфологичните форми се определя от етиологичните фактори, структурните особености на белия дроб, възрастта и реактивността на организма.</p><p><strong>1. Според характера на възбудителя:</strong></p><ul><li>Бактериални (пневмококови, стрептококови, стафилококови, псевдомонасни и др.).</li><li>Вирусни.</li><li>Микоплазмени.</li><li>Паразитни.</li><li>Микотични.</li></ul><p><strong>2. Според патогенезата:</strong></p><ul><li>Аспирационни.</li><li>Хипостатични.</li><li>Травматични.</li><li>Следоперативни.</li></ul><p><strong>3. Според разпространението на процеса:</strong></p><p>Различават се според обхвата в белодробния паренхим (ацинуси, лобули, сегменти или дялове):</p><ul><li>Ацинарни.</li><li>Лобуларни.</li><li>Конфлуиращи (сливащи се).</li><li>Лобарни (дялови).</li><li>Тотални пневмонии.</li></ul><p><strong>4. Според вида на ексудата и протичането:</strong></p><ul><li><strong>Вид на ексудата:</strong> Серозно-десквамативни, фибринозни, гнойни, хеморагични, гнилостни и смесени.</li><li><strong>Протичане:</strong> Остри и хронични.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Вирусни пневмонии</h2><p><strong>Етиология.</strong> Причиняват се най-често от РНК вируси (<span class=\"editor-note\" data-note=\"# Бонус от лекция - Вирус на инфлуенца (Грип)\n**Класификация и епидемиология:**\n* **Тип А:** Причинява пандемии и епидемии поради мутации на хемаглутинина (H) и невраминидазата (N).\n* **Тип В и С:** Засягат предимно деца.\n* **H5N1 (Птичи грип):** Висок леталитет (около 60%). Поради специфичния си хемаглутинин, който се разцепва от протеази в цялото тяло, инфекцията не е локализирана само в белия дроб, а засяга целия организъм.\n**Патоморфология на дихателните пътища:**\n* **Горен респираторен тракт:** Хиперемия, оток и лимфомоноцитна инфилтрация с хиперпродукция на слуз. Може да доведе до запушване на синусите и вторични бактериални инфекции.\n* **Ларинготрахеобронхит:** Оток на гласните връзки и влошена бронхоцилиарна функция.\n* **Бронхиолит:** Запушване на малките въздухоносни пътища от клетъчни остатъци и фибрин, което води до ателектаза.\n**Усложнения:**\n* **Облитериращ бронхиолит:** Организация и фиброза на възпалителните „запушалки“, водещи до перманентно белодробно заболяване.\" id=\"note-1776189550572-26\">грипни</span>, парагрипни, респираторно-синцитиални) и по-рядко от ДНК вируси (аденовируси).</p><p><strong>Патогенеза и морфогенеза.</strong> </p><ul><li><strong>Входна врата:</strong> Респираторният тракт. Вирусите проникват в епителните клетки, размножават се и действат директно цитотоксично.</li><li><strong>Динамика:</strong> Често се наблюдава преминаване на вирусната инфекция в бактериална пневмония, особено при дебилни (изтощени) пациенти.</li></ul><p><strong>Макроскопски.</strong> Обикновено липсват специфични изменения. Наблюдава се катарален ларинго-трахео-бронхит и циркулаторни нарушения (хиперемия, оток) в белите дробове и вътрешните органи.</p><p><strong><span class=\"editor-note\" data-note=\"# Респираторно-синцитиална пневмония\n![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776189265564-image.png &quot;width=100%&quot;)\" id=\"note-1776189268704-25\">Микроскопски</span>.</strong> </p><ul><li><strong>Епителни промени:</strong> <p>Десквамация на бронхиалния и алвеоларния епител</p>. </li><li><strong>Включвания:</strong> В цитоплазмата се наблюдават базофилни включвания (колонии от РНК вируси) или еозинофилни/фуксинофилни такива (реактивен продукт).</li><li><strong><p>Регенерация</p>:</strong> Пролиферация на епитела с образуване на <strong>гигантски многоядрени клетки (симпласти)</strong> и плоскоклетъчна метаплазия.</li><li><strong>Интерстициален компонент:</strong> Оток и обилен мононуклеарен инфилтрат в междуалвеоларните стени (<strong>интерстициална пневмония</strong>). Левкоцитната инфилтрация е белег за вторична бактериална инфекция.</li><li><strong>Аденовирусна пневмония:</strong> Характеризира се с типични „аденовирусни клетки“ и десквамация без последваща регенерация.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\"><strong>Интерстициална пневмония (нз дали влиза)</strong></h2><p><strong style=\"color: rgb(31, 41, 55)\">Етиология.</strong> Най-често се предизвиква от вируси, хламидии и рикетсии.\n<strong>Морфогенеза.</strong> Възпалителният процес е локализиран предимно в <strong>белодробния интерстициум</strong>:</p><ul><li>Стените на алвеолите и алвеоларните ходове;</li><li>Респираторните бронхиоли;</li><li>Перибронхиалната, перивазалната и перилобуларната съединителна тъкан.</li></ul><p>Процесът почти винаги се съчетава с отделяне на ексудат и в алвеолите. Тя може да бъде усложнение на бактериални пневмонии или инфекциозни заболявания (грип, морбили, пертусис). Инфекцията се разпространява по съседство, по хематогенен или лимфогенен път.</p><h3>Микроскопска картина</h3><p>При хистологично изследване се наблюдават следните промени:</p><ul><li><strong>Разширение на преградките:</strong> Междуалвеоларните преградки са значително задебелени поради изразен оток.</li><li><strong>Възпалителен инфилтрат:</strong> Налице е мононуклеарен инфилтрат, съставен от:</li><ul><li>Лимфоцити;</li><li>Хистиоцити;</li><li>Плазматични клетки (понякога).</li></ul><li><strong>Остър характер:</strong> При остро протичане се установяват и неутрофилни левкоцити.</li><li><strong>Алвеоларно засягане:</strong> В някои случаи в лумена на самите алвеоли също се открива ексудат.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 6. Остри бактериални огнищни пневмонии. Бронхопневмония.</h1><h2>Огнищна пневмония (Pneumonia Lobularis)</h2><p><strong>Определение.</strong> Възпаление на белодробния паренхим, което обхваща група от алвеоли, ацини или лобули, обикновено в съчетание с бронхиолит. При сливане на съседни огнища се говори за <em>pneumonia lobularis confluens</em>, което може да ангажира цял сегмент или дял.</p><p><strong>Честота и разпространение.</strong> Много често заболяване, развиващо се предимно като усложнение на други болести (онкологични, сърдечни, ЦНС), след операции или при имунокомпрометирани пациенти.</p><p><strong>Етиология.</strong> Причинява се от широк спектър бактерии (<em>Pneumococci, Staphylococci, Klebsiella, Pseudomonas</em>), вируси и гъбички.</p><p><strong>Морфогенеза.</strong> Основен механизъм е <strong>автоинфекцията</strong>. Поради нарушен дренаж на бронхите, процесът се развива десцентно (<strong>бронхопневмония</strong>). По-рядко инфекцията е хематогенна.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Обща морфологична картина</h3><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776191729536-image.png &quot;width=100%&quot;)\" id=\"note-1776191697266-27\">Макроскопски</span>:</strong></p><ul><li>Уплътнени огнища (2-3 cm), червено-сивкави на цвят.</li><li>Изпъкват над срезната повърхност.</li><li>При натиск изтича мътна безвъздушна течност; паренхимът е лесно къслив.</li></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776191791537-image.png &quot;width=100%&quot;)\" id=\"note-1776191793238-28\">Микроскопски</span>:</strong></p><ul><li>В алвеолите и бронхиолите се открива ексудат: серозна течност, неутрофили, фибрин, еритроцити, макрофаги и десквамирани алвеолоцити.</li><li>Ексудатът варира: серозен, фибринозен, гноен или хеморагичен.</li></ul><p><strong>Изход и усложнения:\n</strong></p><ul><li><strong>Благоприятен изход</strong>: Характеризира се с пълна резорбция на възпалителния ексудат, последвана от възстановяване на белодробния паренхим.</li><li><strong>Усложнения</strong>: </li><ul><li><strong>Организация на ексудата</strong>: При непълна резорбция настъпва процес на организация, водещ до развитие на локализирана <strong>пневмофиброза</strong>.</li><li><strong>Абсцедиране</strong>: При суперпонирана инфекция или висока вирулентност на причинителя може да настъпи тъканна деструкция с формиране на абсцесни кухини.</li><li><strong>Плеврит</strong>: Ангажирането на висцералната плевра е обичайна находка при субплеврална локализация на пневмоничните огнища.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Сравнителна морфология и етиология на видовете огнищна пневмония</h2><h3>Пневмококова огнищна пневмония</h3><ul><li><strong>Етиология</strong>: Причинява се от пневмококи V тип.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776191868085-image.png &quot;width=100%&quot;)\" id=\"note-1776191870350-29\">Макроскопски</span></strong>: Локализира се предимно в долните дялове. Установяват се червено-сивкави уплътнения, които леко изпъкват над повърхността.</li><li><strong>Микроскопски</strong>: В центъра на огнищата ексудатът е предимно от левкоцити и малко фибрин. Периферно се наблюдава изразен оток с наличие на множество пневмококи.</li></ul><h3>Фридлендерова пневмония</h3><ul><li><strong>Етиология</strong>: Причинител е <em>Klebsiella pneumoniae Friedlenderi</em>.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://cdn.ncbi.nlm.nih.gov/pmc/blobs/53d0/7271213/94da1889eb10/f008-040-9780323445856.jpg &quot;width=100%&quot;)\" id=\"note-1776193357895-45\">Макроскопски</span></strong>: Засяга предимно десния бял дроб с големи плътни огнища. При натиск изтича характерен гъст, точещ се слузно-гноен ексудат.</li><li><strong>Микроскопски</strong>: Ексудатът съдържа много левкоцити и бактерии. Често се срещат съдови тромбози и полета на некроза.</li><li><strong>Усложнения</strong>: Често се развива абсцедиране.</li></ul><h3>Стафилококова пневмония</h3><ul><li><strong>Етиология</strong>: Причинява се от <em>Staphylococcus aureus</em> и <em>albus</em>.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://cdn.ncbi.nlm.nih.gov/pmc/blobs/53d0/7271213/7758bfd18b3a/f008-038-9780323445856.jpg &quot;width=100%&quot;)\" id=\"note-1776193313277-44\">Макроскопски</span></strong>: Множество малки тъмночервени огнища. При сливането им се образуват обширни некрози и абсцеси, наподобяващи „пчелна пита“.</li><li><strong>Микроскопски</strong>: Първоначално ексудатът е серозно-хеморагичен, а по-късно се оформя некротично-гноен процес с абсцесни кухини<p>, а в периферията се намира се</p><p>розно-фибринозен ексудат.</p></li><li><strong>Усложнения</strong>: При деца протича тежко. Характерно е развитието на пиопневмоторакс (<em>pyopneumothorax</em>).</li></ul><h3>Стрептококова пневмония</h3><ul><li><strong>Етиология</strong>: Причинява се от бета-хемолитичен стрептокок.</li><li><strong>Макроскопски</strong>: Плътни сивкаво-червени огнища, разположени предимно субплеврално. Придружава се от <span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776191983596-image.png &quot;width=70%&quot;)\" id=\"note-1776191985598-30\">фибринозен плеврит</span>.</li><li><strong>Микроскопски</strong>: <p>В центъра на огнищата се уста</p><p>новява</p>&nbsp;некроза с множество стрептококи, обградена от левкоцитен вал и периферен фибринозен ексудат.</li><li><strong>Характерни белези</strong>: Лимфангит, лимфаденит и тромбофлебит.</li></ul><h3>Пневмоциститна пневмония (Pneumocystosis)</h3><ul><li><strong>Етиология</strong>: Причинява се от <em>Pneumocystis carinii</em>. Среща се при недоносени деца или като опортюнистична инфекция при имунна недостатъчност (СПИН).</li><li><strong>Макроскопски</strong>: Белите дробове са дифузно увеличени, плътни и сивкаво-виолетови.&nbsp;<p>От срезната им повъ</p><p>рхност при натиск оскъдно се отделя слузест ексу</p><p>дат.</p></li><li><strong>Микроскопски</strong>:&nbsp;<p>Алвеолите са изпълнени от кръг</p><p>ли или овални пръстеновидни форми на паразита, </p><p>които поради близкото си разположение една до </p><p>друга създават приликата с \"пчелна пита\".</p> Стените на алвеолите са задебелени и инфилтрирани от лимфоцити.</li></ul><h3>Аспирационна пневмония</h3><ul><li><strong>Етиология</strong>: Вдишване на чужди тела, стомашно съдържимо (при кома или повръщане) или околоплодна течност.&nbsp;<p>Обикновено се развива като <strong>смесена инфекция</strong>, включваща аеробна и анаеробна флора.</p></li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192040377-image.png &quot;width=100%&quot;)\" id=\"note-1776192042400-31\">Макроскопски</span></strong>: <p>Най-често се засягат задно-долните сегменти на белия дроб. Тези зони се характеризират с изразена пъстрота и неравномерна плътност.</p></li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192086675-image.png &quot;width=100%&quot;)\" id=\"note-1776192088714-32\">Микроскопски</span></strong>: Некротично-гноен процес с формиране на абсцеси, в които се откриват аспирираните частици.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 7. Крупозна пневмония – морфологична характеристика.</h1><p><strong style=\"color: rgb(31, 41, 55)\">Определение.</strong> Крупозната пневмония е остро инфекциозно самостоятелно заболяване, ангажиращо един или няколко цели белодробни дяла.</p><p><strong>Синоними:</strong> <u>Лобарна пневмония</u>, фибринозна пневмония, плевропневмония.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Етиология и морфогенеза</h3><ul><li><strong>Причинители:</strong> В <strong>90-95%</strong> от случаите причинителят е пневмококът (<em><strong>Streptococcus pneumoniae</strong></em>) – най-често типове I, II, III (подчертано вирулентен) и VII.</li><li><strong>Механизъм:</strong> Обикновено е <strong>автоинфекция</strong> (активиране на пневмококи в горните дихателни пътища). Рядко може да бъде екзогенна или причинена от <em>Klebsiella</em>, стафилококи или Грам-отрицателни бактерии.</li><li><strong>Патогенеза:</strong> Ключова роля играе <strong>сенсибилизацията</strong> на организма към белтъците на пневмокока с последваща <strong>хиперергична реакция</strong>. Характерно е внезапно начало и бързо обхващане на цели дялове.</li><li><strong>Предразполагащи фактори:</strong> Простуда, физическа и психическа преумора, травма.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3><span class=\"editor-note\" data-note=\"![Image](https://media-us.amboss.com/media/thumbs/big_60ddc09321bbc.jpg &quot;width=100%&quot;)\" id=\"note-1776192183967-33\">Класически стадии на протичане</span></h3><p>Продължителността на заболяването е около <strong>9-11 дни</strong>. </p><p>Характерно за крупозната пневмония е развитието на <strong>ексудативно фибринозно възпаление</strong>, ангажиращо цели дялове (обикновено двата долни и/или средния десен дял), както и надлежащата плевра (фибринозен плеврит). Заболяването протича в четири стадия, като съвременното антибиотично лечение често модифицира или спира тези стадии.</p><h4>1. Стадий на конгестия (Хиперемия) – Продължителност: ~24 часа</h4><ul><li><strong>Макроскопски:</strong> Засегнатият лоб е тежък, интензивно червен, леко уплътнен; крепитациите са едва доловими.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192454394-image.png &quot;width=100%&quot;)\" id=\"note-1776192456076-39\">Микроскопски</span>:</strong> Тежка съдова хиперемия и интраалвеоларен оток с наличие на множество бактерии.</li></ul><h4>2. Стадий на червена хепатизация (<em>Hepatisatio rubra</em>)</h4><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192323326-image.png &quot;width=100%&quot;)\" id=\"note-1776192324968-37\">Макроскопски</span>:</strong> Засегнатият дял е уголемен и плътен като <strong>черен дроб</strong> (хепатизация). Срезната повърхност е червена и финозърниста. По плеврата се появява сивкав, лесно отделящ се <span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192248015-image.png &quot;width=100%&quot;)\" id=\"note-1776192249784-34\">фибринозен ексудат</span>.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192267603-image.png &quot;width=100%&quot;)\" id=\"note-1776192269248-35\">Микроскопски</span>:</strong> Алвеолите са изпълнени с фибрин и еритроцити. Фибриновите нишки преминават през <strong>порите на Cohn</strong> от една алвеола в друга. <p>Ексудатът съдържа и малко количество лев</p><p>коцити и е особено богат на еритроцити.</p></li></ul><h4>3. Стадий на сива хепатизация (<em>Hepatisatio grisea</em>) – Около 4-6-и ден</h4><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192311717-image.png &quot;width=100%&quot;)\" id=\"note-1776192313391-36\">Макроскопски</span>:</strong> <p>Засегнатият дял</p> е тежък, напълно безвъздушен, със сивкава, суха и зърниста срезна повърхност.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192332398-image.png &quot;width=100%&quot;)\" id=\"note-1776192334102-38\">Микроскопски</span>:</strong> Еритроцитите намаляват (хемолиза), неутрофилите се увеличават значително. </li><ul><li><strong>Важен диагностичен белег:</strong> Фибринът се свива и се оформя <strong>светла зона</strong> между ексудата и алвеоларната стена. Това е артефициален хистологичен феномен.</li></ul></ul><h4>4. Стадий на резорбция (<em>Resolutio</em>) – След 8-и ден, с продължителност до 1-3 седмици</h4><ul><li><strong>Механизъм:</strong> Протеолитичните ензими на левкоцитите и макрофагите втечняват ексудата. Той се резорбира в микроциркулацията, поглъща се от макрофагите или се отделя с храчките.</li><li><strong>Изход:</strong> При благоприятен ход белодробната структура се възстановява напълно. Реактивният плеврит, развил се по време на заболяването, може да има подобен изход, но по-често завършва с плеврални сраствания.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Усложнения</h3><h4>Белодробни:</h4><ol><li><strong>Карнификация:</strong> Ексудатът не се резорбира, а прораства от гранулационна тъкан (белият дроб придобива вид на месо).</li><li><strong>Пневмосклероза:</strong> При последващо заместване на гранулационната тъкан с фиброзна.</li><li><strong>Абсцес или гангрена:</strong> При много голяма вирулентност или суперпонирана допълнителна инфекция.</li><li><strong>Емпием на плеврата:</strong> Преминаване на фибринозния плеврит в гноен.</li></ol><h4>Извънбелодробни (Хематогенно/Лимфогенно разпространение):</h4><ul><li>Гноен лимфаденит и медиастинит.</li><li>Перикардит и <strong>язвено-полипозен ендокардит</strong> (често в дясната камера).</li><li>Менингит, перитонит и метастатични мозъчни абсцеси.</li><li>Гнойни артрити.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 8. Микотични пневмонии.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 9. Абсцес и гангрена на белия дроб.</h1><h2>Абсцес на белия дроб (Abscessus pulmonis)</h2><p>Белодробният абсцес е ограничен гнойно-некротичен възпалителен процес, който води до деструкция на паренхима и оформяне на кухина. </p><ul><li><strong>Етиология:</strong> Най-често инфекцията е <strong>смесена</strong>. Основните патогени включват <em>Staphylococcus aureus</em>, <em>Streptococcus viridans</em>, пневмококи и клебсиела.</li><li><strong>Морфогенеза:</strong> Инфектирането се осъществява по няколко пътя:</li><ul><li><strong>Бронхогенен (най-чест):</strong> Чрез аспирация на инфектиран материал (при кома, алкохолизъм, анестезия или стоматологични интервенции), <p>при карцином на бронха, бронхиек</p><p>тазии, панбронхит</p></li><li><strong>Пневмогенен:</strong> Като директно усложнение на крупозна или огнищна пневмония.</li><li><strong>Хематогенен:</strong> При септикопиемия или чрез пренос на септични емболи при тромбофлебити (<p>гноен отит, мастоидит </p><p>с тромбоза на венозните синуси на мозъчните об</p><p>вивки)</p>.</li></ul></ul><p><strong>Патоморфологична характеристика:</strong></p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192999701-image.png &quot;width=100%&quot;)\" id=\"note-1776193001726-42\">Макроскопски</span>:</strong> Могат да бъдат единични или ножествени. Абсцесите са кръгловати кухини (от няколко мм до 6 см), изпълнени с жълта или зеленикава гной. <p>По-големите кухини комуникират с т.нар. „дрениращи бронхи“.</p> <strong>Аспирационните </strong>абсцеси са локализирани предимно в <strong>долните дялове на десния бял дроб</strong>, поради по-вертикалния ход на десния главен бронх. <p><strong>Хематогенните </strong>абсцеси са малки и са </p><p>разпръснати навсякъде в белодробния паренхим. </p></li></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776192086675-image.png &quot;width=100%&quot;)\" id=\"note-1776193043898-43\">Микроскопски</span>:</strong> Стената на <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776193394077-image.png &quot;width=100%&quot;)\" id=\"note-1776193397500-46\">острия </span></strong>абсцес е изградена от некротична и гнойно инфилтрирана тъкан. При <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776193415703-image.png &quot;width=100%&quot;)\" id=\"note-1776193417738-47\">хроничния</span> </strong>се формира <strong>пиогенна мембрана</strong> от гранулационна и съединителна тъкан.</p><p><strong>Изход и усложнения:</strong></p><ul><li><strong>Изход:</strong> Възможно е пълно оздравяване, при което кухината се запълва с гранулационна тъкан и се оформя <strong>цикатрикс</strong>.</li><li><strong>Усложнения:</strong> Гноен плеврит, метастатични абсцеси (най-често в главния мозък), гноен менингит и вторична амилоидоза при хронично протичане.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Гангрена на белия дроб (Gangraena pulmonis)</h2><p>Гангрената представлява най-тежката форма на белодробна деструкция. Тя е остро некротично възпаление, което протича дифузно и без ясна граница от здравата тъкан.</p><ul><li><strong>Етиология:</strong> Предизвиква се от специфична <strong>анаеробна флора</strong>, фузиформени бактерии, спирили и <em>Bacterium perfringens</em>.</li><li><strong>Морфогенеза:</strong> Обикновено се развива като вторичен процес у силно изтощени хора, чийто организъм не може да ограничи абсцедираща пневмония или абсцес.</li></ul><p><strong>Патоморфологична характеристика:</strong></p><ul><li><strong>Макроскопски:</strong> Засегнатата част има <strong>мръсно сиво-зелен до кафяв цвят</strong> и излъчва тежка гнилостна миризма. Тъканта е изключително къслива. Виждат се неправилни кухини с <strong>разръфани краища</strong>, изпълнени с детритна материя.</li><li><strong>Микроскопски:</strong> Наблюдават се обширни полета на некроза и кръвоизливи. Характерен белег е некротичното засягане на кръвоносните съдове, което води до масивни <strong>тромбози</strong>, ускоряващи разпада на органа.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 10. Алергични заболявания на белите дробове – видове. Бронхиална астма.</h1><h3>БРОНХИАЛНА АСТМА (ASTHMA BRONCHIALE)</h3><p><strong>Определение</strong> Бронхиалната астма е хронично алергично заболяване, характеризиращо се с пристъпи на задух. Те се дължат на <strong>бронхиална обструкция</strong>, предизвикана от два основни фактора:</p><ul><li>Спазъм на гладката мускулатура на бронхите.</li><li>Обилна секреция на гъста слуз в бронхиалния лумен.</li></ul><p>Въз основа на отключващите фактори заболяването се класифицира в два основни вида:</p><ul><li><p><strong>Външна (атопична, алергична):</strong> Предизвиква се от екзогенни алергени като храна, полени, прах и други. Този тип е класическа реакция на свръхчувствителност от I тип (IgE-медиирана).</p><br></li><li><p><strong>Вътрешна (неатопична):</strong> Инициира се от инфекции (често вирусни), лекарства (например аспирин), химични дразнители и други неалергични фактори.</p><br></li></ul><p><strong>Морфогенеза: </strong>Антигените се свързват с клетъчно-свързаните IgE антитела (разположени по повърхността на мастоцити, базофилни и плазматични клетки, лимфоцити). Това води до освобождаване на биологично активни вещества, като хистамин, серотонин, кинини и други медиатори, което предизвиква:</p><ol><li><p>Спазъм на гладката мускулатура на бронхите (бронхоспазъм).</p>.</li><li>Хиперсекреция на слуз.</li><li><p>Съдова реакция с оток на лигавицата</p>.</li></ol><h3>Патоморфологична картина</h3><p><strong>Макроскопски находки</strong> \nНай-изразени са при смърт по време на пристъп (<strong>status asthmaticus</strong>):</p><ul><li><p>Белите дробове са силно раздути и с бледорозов цвят, което е израз на <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776201076868-image.png &quot;width=100%&quot;)\" id=\"note-1776201322511-53\">остър емфизем</span></strong>. </p></li><li><strong></strong><p>Виждат се малки, хлътнали, тъмночервени полета, представляващи огнищни ателектази (поради запушване на бронхи от слуз).</p></li><li>Бронхите са изпълнени с голямо количество гъста, трудно отделяща се слуз, оформяща слузни запушалки.</li></ul><p><strong>Микроскопски находки\n</strong></p><p>Лигавицата на бронхите е хиперемирана и показва белези на алергично възпаление и структурни промени, подредени според местоположението си:</p><ul><li style=\"font-weight: bold\"><strong><p>В бронхиалния лумен:</p></strong></li><ul><li><p>Слузни запушалки, които са богати на <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776201530944-image.png &quot;width=100%&quot;)\" id=\"note-1776201532247-56\">еозинофилни левкоцити</span></strong>.</p></li><li><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776201496901-image.png &quot;width=100%&quot;)\" id=\"note-1776201497885-55\">Кристали на Charcot-Leyden</span></strong>, които представляват кристализирали мембранни протеини от разпаднали се еозинофили.</p></li><li><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776201487934-image.png &quot;width=100%&quot;)\" id=\"note-1776201489253-54\">Спирали на Curschmann</span></strong>, представляващи спираловидни образувания от слуз и десквамиран епител.</p></li></ul><li><strong>В бронхиалния епител</strong>:</li><ul><li>Явления на десквамация на бронхиалния епител.</li><li>Хиперплазия на бронхиалния епител с изразена <strong>чашковидноклетъчна метаплазия</strong>. Това означава, че мнозинството от епителните клетки се превръщат в слуз-секретиращи чашковидни клетки (докато при нормална белодробна тъкан те са около 20%).</li></ul><li><strong>В задебелената бронхиална стена:</strong></li><ul><li>Присъствие на възпалителен инфилтрат, съставен от еозинофилни левкоцити, лимфоцити и мастоцити.</li><li>Наличие на <strong>оток</strong>, <strong>хиперемия </strong>и <strong>фиброза</strong>.</li><li><strong>Хиперплазия на гладката мускулатура на бронхите</strong> (което обяснява силния спазъм).</li><li><p>Базалните мембрани са силно <strong>задебелени и хиалинизирани</strong>.</p></li></ul></ul><h3>Усложнения при хронично протичане</h3><p>Дълготрайната астма води до трайни структурни изменения в дихателната и сърдечно-съдовата система:</p><ul><li>Хроничен обструктивен емфизем.</li><li>Бронхиектазии.</li><li><strong>Хронично белодробно сърце (Cor pulmonale chronicum):</strong> Поради повишеното съпротивление в малкия кръг на кръвообращението.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Еозинофилна пневмония на Льофлер (Белодробна еозинофилия, Алергична пневмония)</h2><p><strong>Етиология и морфогенеза:</strong> Алергична реакция към медиатори, химични вещества, гъбички (Aspergillus) или паразити (ларви на Ascaris lumbricoides).</p><p><strong>Микроскопски</strong>. Задебелени междуалвеоларни преградки с <strong>еозинофилен инфилтрат </strong>и <strong>гигантски клетки</strong>. Подобни промени има в стените на малките бронхи.</p><p><strong>Изход</strong>. Изключително благоприятна; преминава за 1-2 седмици.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Алергичен алвеолит (Хиперсензитивен пневмонит)</h2><p>Това е имуномедирано заболяване на белодробния паренхим, причинено от повтаряща се инхалация на органични антигени. Прототипът е <strong>„фермерски бял дроб“</strong>, но се описват и форми като „бял дроб на гледачи на гълъби“, „багазоза“ (при работа със захарна тръстика) и други.</p><ul><li><strong>Етиология и патогенеза:</strong> Причинява се от термофилни актиномицети, гъбични спори или животински протеини. Развива се свръхчувствителност от <strong>имунокомплексен характер</strong> (тип III) с фиксация на комплемента, в която участват активно лимфоцити и макрофаги.</li><li><strong>Микроскопска картина:</strong></li><ul><li><strong>Остър стадий:</strong> Характеризира се с алвеоларен оток и интерстициална инфилтрация от неутрофили, еозинофили и макрофаги. В около 50% от случаите се развива <strong>облитериращ бронхиолит</strong>, като около засегнатите бронхиоли се наблюдават групи от пенести клетки.</li><li><strong>Хроничен стадий:</strong> Доминира интерстициалната фиброза и облитериращият алвеолит. Възпалението е <strong>бронхиолоцентрично и грануломатозно</strong>, като между патологичните огнища белодробната тъкан остава незасегната.</li></ul><li><strong>Клинична картина и изход:</strong> Проявява се с температура, кашлица и диспнея. Изходът обикновено е благоприятен при навременно изолиране от антигенната среда и лечение с кортикостероиди.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Алергична грануломатоза на Churg-Strauss (Чърч-Щраус)</h2><p>Рядко системно заболяване, което патоморфологично се разглежда като междинен стадий между еозинофилната пневмония на Löffler и грануломатозата на Wegener.</p><ul><li><strong>Макроскопски белези:</strong> В белите дробове, но също и в миокарда, слезката и бъбреците, се установяват сиво-жълти възли с диаметър до 15 mm. Бронхиалните стени са задебелени, а лумените им са изпълнени с характерна гъста слуз.</li><li><strong>Микроскопска картина:</strong> Установяват се множество <strong>туберкулоподобни грануломи</strong> с централна зона на некроза. Около нея радиално са подредени епителоидни клетки, гигантски многоядрени клетки тип „чуждо тяло“, лимфоцити и масивно количество еозинофилни левкоцити. В някои от случаите, в малки и среднокалибрени съдове, се намира картината на <strong>некротизиращ васкулит</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Синдром на Wegener (Грануломатоза на Wegener)</h2><p>Тежко, системно автоимунно заболяване с неизяснена етиология, което се характеризира с деструктивни промени в респираторния тракт и бъбреците.</p><ul><li><strong>Клинико-морфологична триада:</strong></li><ol><li>Грануломатозно възпаление на горните и долните дихателни пътища.</li><li>Генерализиран некротичен васкулит на малките съдове.</li><li>Огнищен некротичен гломерулонефрит.</li></ol><li><strong>Макроскопска картина:</strong> Околоносните синуси са изпълнени с гной и тъканен детрит, често с костна деструкция. По лигавицата на трахеята и бронхите се наблюдават разязвявания. В белите дробове се откриват плътни, добре отграничени сиво-жълти възли, които морфологично наподобяват туберкулозни огнища.</li><li><strong>Микроскопска картина:</strong> Огнищата имат централна некроза, обградена от епителоидни клетки, фибробласти и еозинофили. Присъстват гигантски клетки (тип Langhans и тип „чуждо тяло“). Ключова находка е <strong>некротичният васкулит </strong><p>в белите дробо</p><p>ве и в други вътрешни органи </p><p>и <strong>огни</strong></p><p><strong>щен некротичен гломерулонефрит</strong>.</p></li><li><strong>Изход:</strong> Често неблагоприятен. Основната причина за летален изход е прогресиращата бъбречна недостатъчност.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 11. Обструктивни белодробни заболявания. Емфизем. Морфологична характеристика.</h1><h2>Хронична обструктивна белодробна болест (ХОББ)</h2><p><strong>ХОББ</strong> е обединяващ термин за група заболявания (<strong>емфизем, хроничен бронхит, бронхиална астма и бронхиектазии</strong>), които протичат с хронична или повтаряща се обструкция на дихателните пътища (бронхи, терминални и респираторни бронхиоли).</p><ul><li><strong>Основен симптом:</strong> Задух.</li><li><strong>Етиология:</strong> Замърсяване на околната среда и тютюнопушене. Тези фактори водят до значителна честота на заболяването и инвалидизация на болните.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Емфизем на белите дробове (Emphysema Pulmonum)</h2><p><strong>Определение:</strong> Състояние, характеризиращо се с наднормено увеличаване на размера на въздушните пространства, разположени дистално от терминалните бронхиоли, съпроводено с <strong>разрушаване на алвеоларните стени</strong>.</p><p><strong>Честота:</strong> Засяга по-често мъже, извършващи тежък физически труд, живеещи в запрашена среда, влага и студ, както и лица с вредни навици (пушене, алкохолизъм).</p><h3>Морфологична класификация</h3><p>Разделя се според локализацията на измененията в белодробното делче (ацинуса):</p><ol><li><strong>Центроацинарен (центролобуларен):</strong> Разширяват се респираторните бронхиоли (проксималната част на ацинуса). Те изглеждат като кухини, обградени от непроменени алвеоли в дисталната част. Среща се най-често в горните дялове и най-вече в апикални им сегменти.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776260025739-image.png &quot;width=100%&quot;)\" id=\"note-1776260027810-65\">Панацинарен </span>(панлобуларен):</strong> Ангажиран е целият ацинус. Раздуването обхваща равномерно респираторните бронхиоли и алвеолите. По-често се засягат долните части на белите дробове.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776260035497-image.png &quot;width=100%&quot;)\" id=\"note-1776260037435-66\">Парасептален </span>(дистално ацинарен):</strong> Измененията са в дисталната част на ацинуса. По-ясно изразен под плеврата и покрай съединителнотъканните септи <p>и границите на лобулите, обикновено в горната </p><p>половина на белите дробове</p>. Може да формира кистоподобни структури (<strong>були</strong>) с диаметър от 0,5 до 2 cm.</li><li><strong>Перицикатриксиален (ирегуларен):</strong> Неравномерно и неправилно раздуване на ацинуса, почти винаги в съседство с цикатрикс.</li><li><strong>Смесен:</strong> Комбинация от горните форми.</li></ol><h3>Клинико-морфологична класификация</h3><h4>1. Субстанциален (алвеоларен) емфизем</h4><p><strong>1.1. Първичен емфизем</strong></p><ul><li><strong>Първичен идиопатичен:</strong> Наблюдава се рядко след 30-годишна възраст. Свързва се с <strong>вроден дефицит на алфа-1-антитрипсин</strong>. Настъпва дисбаланс, при който протеолитичните ензими (<strong>еластаза</strong>), отделяни от неутрофилите и макрофагите, разрушават алвеоларните стени. Представя се като панацинарен емфизем.</li><li><strong>Първичен старчески (Emphysema senile):</strong> Проява на обща атрофия. Настъпват дегенеративни промени в еластичните влакна без деструкция на паренхима. Дихателната недостатъчност е незначителна, не се развива белодробна хипертония.</li><ul><li><strong>Макроскопски:</strong> Дробовете са сиво-розови, отпуснати, меки и лесно късливи. <p>При от</p><p>варянето на гръдния кош те бързо се свиват към хил</p><p>уса.</p></li><li><strong>Микроскопски:</strong> <p> Гладката мускулатура на респираторните бронхиоли е атрофична. Силно са дилатирани </p><p>алвеоларните ходове и в по-слаба степен алвеолите. Поради сливане в лентовидни снопчета, еластичните </p><p>влакна в стените на алвеолите изглеждат задебелени</p>.</li></ul></ul><p><strong>1.2. Вторичен емфизем</strong></p><ul><li><strong>Остър компенсаторен (Викарен):</strong> </li><ul><li><p><strong>Етиология</strong>. Развива се при оперативно отстраняване или изключване от функция поради патологични </p><p>процеси (ателектаза, тумори, туберкулоза, пневмосклероза) на сегменти от белите дробове, на техни дялове </p><p>или на единия бял дроб.</p></li><li><p><strong>Морфогенеза</strong>. </p><p>Алвеолите се раздуват компенсаторно без разрушаване на стените</p>. <p>Това се приема като компенсаторно-приспособителна реакция на остатъчната белодробна тъкан</p><p>.</p></li><li><p><strong>Макроскопски</strong>. Части от белите дробове са с увеличен обем, с бледорозово-сивкав цвят, кредитиращи при </p><p>опипване.</p></li><li><p><strong>Микроскопски</strong>. Алвеоларните ходове и алвеоли са силно разширени и със значително изтънели стени. </p></li></ul><li><strong>Остър дифузен:</strong> </li><ul><li><p><strong>Морфогенеза</strong>. </p><p>При това състояние настъпва с</p>връхостро раздуване при задушаване, удавяне или астматичен пристъп</li><li><p><strong>Макроскопски</strong>. Белите дробове са силно раздути, с бледосивкав цвят. Тъй като в белодробния паренхим не </p><p>настъпват структурни промени, след притискане с ръце</p><p>те могат да възстановят своята форма и големина.</p></li><li><p><strong>Микроскопски</strong>. Намират се преразтегнати и деформирани алвеоларни ходове и алвеоли със силно изтънели </p><p>стени.</p></li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>2. Хроничен дифузен (обструктивен) емфизем</h3><p>Това е най-честата форма на емфизем с решаващо клинично значение, поради тежките промени, които предизвиква в белите дробове и сърцето.</p><h3>1. Етиология и патогенеза</h3><ul><li><strong>Бронхиална обструкция:</strong> Основен фактор е хроничният бронхит и бронхиолит. Възпалението, спазъмът на мускулатурата и натрупването на гъст секрет (\"запушалки\") стесняват лумена на бронхите.</li><li><strong>Механизъм на \"вентилна стеноза\":</strong> При вдишване (активен процес) въздухът преминава през стеснения участък, но при пасивно издишване бронхите колабират преждевременно. Част от въздуха се задържа, повишавайки налягането и разширявайки ацинуса.</li><li><strong>Протеазно-антипротеазна хипотеза:</strong> Дължи се на дисбаланс в белия дроб. Еластазата (протеаза), отделяна от левкоцитите при възпаление, разрушава еластичната тъкан. Този деструктивен ефект се засилва при дефицит на <strong>алфа-1-антитрипсин</strong> (главен инхибитор) или неговото инактивиране от оксидантите в цигарения дим&nbsp;<p>и свободните кислородни радикали, отделяни от макрофагите и неутрофилните </p><p>левкоцити.</p></li></ul><h3>2. Морфогенеза и Сърдечни промени</h3><p>Преразтягането на ацинуса води до изтъняване на еластичните влакна и критична редукция на капилярната мрежа.</p><ul><li><strong>Алвеоларно-капилярен блок:</strong> В преградите разраства колаген, което затруднява газообмена и кръвообращението (интракапилярна склероза).</li><li><strong>Cor Pulmonale:</strong> Повишеното интрапулмонално налягане води до <strong>хипертрофия и дилатация на дясната камера</strong>. В крайните стадии сърдечната недостатъчност става водеща.</li></ul><h3>3. Патоморфология</h3><ul><li><strong>Макроскопски:</strong> Белите дробове са силно раздути, изпълват гръдната кухина и не колабират при отварянето ѝ, като припокриват сърцето. Еластичността е загубена – при натиск остава бавно изглаждащо се хлътване. Палпаторно се долавят <strong>крепитации</strong>. По повърхността често се виждат булозни раздувания.</li><li><strong>Микроскопски:</strong> Наблюдава се преустройство на ацините (центроацинарно или панацинарно). Алвеолите са с изгладени дъна, а алвеоларните ходове приличат на големи кухини.</li><li><strong>Характерен белег:</strong> Свободният край на притварящите пластинки на респираторните бронхиоли задебелява и придобива вид на <strong>бухалка</strong>.</li><li><strong>\"Чезнещ бял дроб\" (Vanishing lung):</strong> Най-тежката форма, при която преградките между няколко лобула атрофират напълно и се сливат в огромни общи кухини.</li></ul><h3>4. Усложнения и Изход</h3><ul><li><strong>Усложнения:</strong> Хронични възпалителни процеси поради нарушен дренаж и риск от <strong>пневмоторакс</strong> при разкъсване на разширените алвеоли или були.</li><li><strong>Изход:</strong> Прогнозата е неблагоприятна. Болните загиват от прогресираща дихателна и десностранна сърдечна недостатъчност.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Хроничен огнищен (перицикатрициален) емфизем</h3><ul><li><strong>Етиология:</strong> Развива се около зони на <strong>пневмофиброза</strong>.</li><li><strong>Морфогенеза:</strong> Алвеолите се раздуват поради притискане на бронхите от фиброзата или механично придърпване от разрасналата фиброзна тъкан.</li><li><strong>Макроскопия:</strong> Наличие на <strong>були</strong> (въздушни мехури) с размери от лешник до кокоше яйце около уплътнени полета.</li><li><strong>Микроскопия:</strong> Ирегуларен емфизем.</li><li><strong>Риск:</strong> Разкъсване на булите води до <strong>пневмоторакс</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Интерстициален емфизем</h3><p>Въздухът напуска алвеолите и навлиза в интерстициума на белия дроб.</p><ul><li><strong>Морфогенеза:</strong> <p>Настъпва при нарушаване целостта на паренхима. Въздухът излиза от дихателните пътища и навлиза в тъканта около бронхите и съдовете.</p></li><ul><li><p><strong>Причини</strong>: Силна, раздираща кашлица (грип, морбили, пертусис/коклюш) или механична травма (фрактури на ребра).</p></li></ul><li><p><strong>Пътища на разпространение:</strong></p><br></li><ul><li><p>Достига под висцералната плевра.</p></li><li><p>Придвижва се към хилуса и медиастинума (<strong>медиастинален емфизем</strong>), където може да притисне големите кръвоносни съдове.</p></li><li><p>Преминава в подкожната тъкан на шията, лицето или гръдния кош (<strong>подкожен емфизем</strong>).</p></li></ul><li><strong>Макроскопия:</strong> Под плеврата се виждат въздушни мехурчета (2-5 mm), наредени като <strong>броеница</strong>.&nbsp;<p>При подкожен емфизем кожата е силно раздута, а при палпация се усещат характерни <strong>крепитации</strong>.</p></li><li><strong>Изход:</strong> Обикновено въздухът се резорбира бързо, но е възможен и пневмоторакс при разкъсване на плеврата.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 12. Oбструктивни белодробни заболявания. Бронхиектазии. Морфологична характеристика.</h1><h2>Определение и същност</h2><p>Бронхиектазиите представляват <strong>перманентна дилатация</strong> на бронхи и бронхиоли поради деструкция на еластична и мускулна тъкан. Когато към тези разширения се добави инфекция и възникне хроничен възпалителен процес, състоянието се определя като <strong>бронхиектатична болест</strong>.</p><h2>Етиология и морфогенеза</h2><p>В зависимост от механизмите на възникване, те се делят на две основни групи:</p><ul><li><strong>Вродени бронхиектазии:</strong> Дължат се на ембрионални нарушения в развитието на бронхиалното дърво <p>и нерядко се съчетават с пороци в развитието и на други органи.</p></li><li><strong>Придобити бронхиектазии:</strong> За тяхното развитие са ключови два процеса — <strong>бронхиална обструкция</strong> и <strong>персистираща хронична инфекция</strong>. Тези процеси взаимно се подсилват в патогенетичен порочен кръг.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Макроскопска и микроскопска картина (Вродени)</h2><p><strong>Макроскопски.</strong> При вродените бронхиектазии се различават две форми:</p><ol><li><strong>Едрокистичен бял дроб:</strong> Дяловите и сегментните бронхи завършват сляпо в интерстициума, оформяйки големи кисти.</li><li><strong>Дребнокистична форма:</strong> Разширение на терминалните бронхиоли (картина, наподобяваща емфизем).</li></ol><p><strong>Микроскопски.</strong> В стените се открива безпорядъчно разположение на структурните елементи. Обичайно липсва изразена пневмосклероза и отлагане на антракотичен пигмент.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация</h2><p><strong>Според формата:</strong></p><ul><li>Цилиндрични (<em>bronchiectasiae cylindriformes</em>);</li><li>Вретеновидни (<em>bronchiectasiae fusiformes</em>);</li><li>Торбовидни (<em>bronchiectasiae sacciformes</em>).</li></ul><p><strong>Според разпространеността:</strong></p><ul><li>Дифузни и ограничени.</li></ul><p><strong>Според механизма на възникване:</strong></p><ul><li><strong>Ретенционни </strong>-&nbsp;<p>Възникват в хода на <strong>дълготраен хроничен бронхит</strong>. Настъпва отслабване на стените и задръжка на секрет. Упоритата кашлица с тласъчно повишаване на ендобронхиалното налягане предизвиква трайно разширяване. Обичайно са <strong>цилиндрични </strong>и <strong>дифузни</strong>.</p></li><li><strong>Деструктивни </strong>-&nbsp;<p>Възникват при нагнояване и деструкция на стената (<strong>гноен панбронхит</strong>). Срещат се при туберкулоза, морбили, пертусис и грип. Често имат преходен характер (<strong>транзиторни</strong>) и са <strong>торбовидни</strong>.</p></li><li><strong>Ателектатични бронхиектазии</strong> -&nbsp;<p>Появяват се след плеврални сраствания или пневмосклероза, които фиксират паренхима към гръдната стена и „разпъват“ бронхите. Обикновено имат <strong>торбовидна </strong>форма.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоморфология (Придобити)</h2><p><strong>Макроскопски:</strong></p><ul><li><strong>Цилиндрични бронхиектазии:</strong> Почти равномерно разширен просвет, проследим до самата плеврална повърхност.</li><li><strong>Торбовидни бронхиектазии:</strong> Различно големи кухини, свързани с бронхите, но оградени от плътна, безвъздушна белодробна тъкан.</li><li><strong>Общи белези:</strong> Стените са неравномерно изтънели, а лумените често са изпълнени със секрет или гноен ексудат.</li></ul><p><strong>Микроскопски:\n</strong>Наблюдава се частична или пълна <strong>атрофия</strong> на гладката мускулатура, жлезите и хрущялните пластинки, които се заместват от съединителна тъкан (фиброза).</p><ul><li><strong>Епителни промени:</strong></li><ul><li>При <strong>цилиндричните </strong>– висок цилиндричен епител, често с участъци на десквамация или <strong>плоскоклетъчна метаплазия</strong>.</li><li>При <strong>торбовидните </strong>– тапицирани с <strong>многослоен плосък епител</strong>, разположен директно върху фиброзна тъкан (без базална мембрана).</li></ul><li><strong>Околна тъкан:</strong> Възпалителни инфилтрати в стената и съседни пневмонични огнища, често с белези на <strong>карнификация</strong> или изразена пневмосклероза.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения</h2><p><strong>Белодробни усложнения:</strong></p><ul><li>Огнищни пневмонии.</li><li>Абсцеси и гангрена (при аспирация на гноен ексудат).</li></ul><p><strong>Извънбелодробни усложнения:</strong></p><ul><li>Хронично белодробно сърце (<em>Cor pulmonale</em>).</li><li>Метастатични абсцеси в мозъка.</li><li>Сепсис.</li><li><strong>Вторична амилоидоза</strong>.</li><li>Хипертрофична остеоартропатия (<strong>„<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776188052015-image.png &quot;width=100%&quot;)\" id=\"note-1776188053830-23\">барабанни пръсти</span>“</strong>).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 13. Хронични дифузни интерстициални (рестриктивни) заболявания – видове. Пневмокониози.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 14. Белодробна хипертония – етиология. Белодробно сърце – морфологична характеристика.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 15. Остър респираторен дистрес синдром. Етиология, морфологична характеристика.</h1><h2>Респираторен дистрес синдром при възрастни</h2><p><strong>Синоними:</strong> Шоков бял дроб, Дифузно алвеоларно увреждане, Остро алвеоларно увреждане.</p><p><strong>Етиология и механизъм на увреждане\n</strong>Синдромът е израз на тежка реакция на белия дроб към системни или директни увреждания. Причините са разнообразни:</p><ul><li><strong>Шокови състояния:</strong> Септичен, анафилактичен, хеморагичен или кардиогенен шок.</li><li><strong>Интоксикации:</strong> Екзогенни (наркотици, вдишване на 70-100% чист кислород, токсични газове като хлор и азотен диоксид) и ендогенни (уремия).</li><li><strong>Инфекции и травми:</strong> Тежки вирусни пневмонии, аспирация на стомашно съдържимо, обширни изгаряния или комбинирани полиорганни травми.</li></ul><p>Патогенетично процесът започва с увреждане на <strong>капилярния ендотел</strong> и <strong>алвеолоцитите</strong>. Това рязко повишава пропускливостта на алвеоло-капилярната мембрана, което води до преминаване на богата на протеини течност първо в интерстициума, а след това и в алвеоларните пространства (алвеоларен оток).</p><p><strong>Патоморфологични белези</strong></p><ul><li><strong>Макроскопски:</strong> Дробовете са тежки, оточни, с „тестовидна“ консистенция и тъмночервен цвят. Срезните повърхности са гладки и блестящи, като при натиск изтича обилна розова пенеста течност (течност, примесена с въздух и кръв).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776251638491-image.png &quot;width=100%&quot;)\" id=\"note-1776251641317-57\">Микроскопски</span>:</strong> </li><ul><li>В ранната фаза доминират капилярното кръвонапълване и отока.</li><li>Най-характерни са <strong>хиалинните мембрани</strong> – интензивно розови, панделковидни структури, тапициращи алвеолите. Те се състоят от фибрин, плазмени белтъци и остатъци от некротични клетки.</li><li>Често се наблюдават фибринни тромби в микроциркулацията (белег на ДИК синдром).</li><li><p>В по-късните фази настъпва организация с <strong>интерстициална </strong>и <strong>интраалвеоларна фиброза</strong>. Наблюдава се пролиферация на <strong><span class=\"editor-note\" data-note=\"(кубични или цилиндрични клетки)\" id=\"note-1776251797388-59\">алвеолоцити от тип II</span></strong>, които покриват увредените алвеоларни стени.</p></li></ul></ul><p><strong>Изход и организация\n</strong>Около половината от случаите завършват фатално в първите дни. При по-голямата част от преживелите е възможно пълно възстановяване. По-рядко се развива трайна интерстициална и интраалвеоларна фиброза.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Респираторен дистрес синдром при новородени</h2><p><strong>Синоним:</strong> Хиалинно-мембранна болест (ХМБ).</p><p><strong>Етиология и патогенеза\n</strong></p><p>Водещата причина за развитието на синдрома е <strong>дефицитът или инактивацията на белодробния сърфактант</strong>, което се наблюдава най-често при недоносени деца. Сърфактантът е от съществено значение за намаляване на повърхностното напрежение в алвеолите и поддържането им в разгънато състояние.</p><p>Допълнителни утежняващи фактори са:</p><ul><li>Фетална асфиксия.</li><li>Аспирация на околоплодна течност.</li><li>Нарушения в микроциркулацията, които водят до повишен капилярен пермеабилитет.</li></ul><p>Вследствие на тези процеси, плазмените белтъци излизат в алвеоларните пространства, където преципитират и формират хиалинни мембрани.</p><p><strong>Патоморфологична картина</strong></p><ul><li><strong>Макроскопски:</strong> Белите дробове са плътни, безвъздушни и с тъмночервен цвет. Изключително важен диагностичен белег е, че <strong>потъват във вода</strong> (поради липсата на въздух).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776251731094-image.png &quot;width=100%&quot;)\" id=\"note-1776251733190-58\">Микроскопски</span>:</strong> Наблюдава се характерната картина тип <strong>„швейцарско сирене“</strong>:</li><ul><li>Повечето алвеоли са дифузно <strong>колабирали </strong>(ателектаза).</li><li>На техния фон се виждат отделни, парадоксално <strong>разширени </strong>респираторни бронхиоли и алвеоларни ходове.</li><li>Тези разширени пространства са тапицирани с хиалинни мембрани, което придава специфичния вид на хистологичния препарат.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 16. Ателектаза (колапс) на белия дроб. Видове, морфологична характеристика.</h1><p><strong>Определение:</strong> Състояние на непълно разгъване на белодробния паренхим или свиването му, след като той вече е функционирал (в последния случай по-правилният термин е <strong>белодробен колапс</strong>). При ателектазата въздухът в засегнатата част напълно липсва или е силно намален.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776200339977-image.png &quot;width=100%&quot;)\" id=\"note-1776200342042-48\">Класификация според механизма на възникване</span></h3><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fimage.slidesharecdn.com%2Fchestxraybasicinterpretation-160730070231%2F95%2Fchest-x-ray-basic-interpretation-29-638.jpg%3Fcb%3D1469862189&amp;f=1&amp;nofb=1&amp;ipt=be9d04110ac81a583838c421af759f1e185047e536ab984b5131b28a74d322d8 &quot;width=100%&quot;)\" id=\"note-1776200730823-49\">Обтурационна (резорбционна)</span>:</strong> Дължи се на механично запушване на бронх (тумор, чуждо тяло, секрет). Въздухът дистално от запушването се резорбира и тъканта колабира.</li><li><strong>Компресионна:</strong> Получава се при натиск върху паренхима отвън. Причини могат да бъдат патологични процеси в плевралната (пневмоторакс, плеврит, тумор) или в коремната кухина (субдиафрагмален абсцес, следоперативни състояния).</li><li><strong>Контракционна:</strong> Среща се при ограничаване на разгъването на белия дроб от огнищни фибро-склеротични процеси в него.</li><li><strong>Сърфактантдефицитна:</strong> <p>Увреждане на сърфактанта настъпва при вдишва</p><p>не на разграждащи го вещества (спирт, етер, ке</p><p>росин, газове при горене на лакове и пластмаси</p><p>), при продължително инхалиране на чист </p><p>кислород и др. С недостига на сърфактант се </p><p>обяснява ателектазата, която може да се развие </p><p>няколко часа след раждане, особено у недоносе</p><p>ни.</p></li><li><strong>Фетална (първична):</strong> Наблюдава се у новородени, при които дробът изобщо не се е разгънал поради незрялост, вътреутробна асфиксия с аспирация на околоплодни води.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Патоморфологична картина</h3><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776200772184-image.png &quot;width=100%&quot;)\" id=\"note-1776200773452-50\">Макроскопски белези</span>:</strong></p><ul><li><strong>Цвят и повърхност:</strong> Ателектатичните участъци са <strong>тъмночервени</strong>, „месести“ и хлътнали под нивото на плеврата. По-старите огнища изглеждат сиво-черни поради натрупване на въглищен прах.</li><li><strong>Размер:</strong> Засегнатият сегмент или дял е намален по размер. При тотална ателектаза (у мъртвородени) белите дробове потъват във вода.</li><li><strong>Медиастинум:</strong> Характерно е изместване на медиастинума към страната на ателектатичния бял дроб.</li></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-14/text-editor-images/2026/04/1776200808501-image.png &quot;width=100%&quot;)\" id=\"note-1776200809787-51\">Микроскопски белези</span>:</strong></p><ul><li>Алвеолите са със силно намалена площ (притиснати).</li><li>Перилобуларните преградки, бронхите и кръвоносните съдове са приближени едни до други. Наблюдава се силно кръвонапълване на съдовете.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Прогноза и усложнения</h3><ul><li><strong>Изход:</strong> При отстраняване на причината е възможно <strong>пълно възстановяване</strong> на структурата.</li><li><strong>Ателектатична пневмония:</strong> Поради влошения дренаж, в ателектатичните участъци лесно се развива възпалителен процес.</li><li><strong>Постателектатична пневмосклероза:</strong> При продължително съществуваща ателектаза паренхимът се заменя от съединителна тъкан.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 17. Белодробен оток. Патогенеза, морфологична характеристика.</h1><p>Белодробният оток представлява патологично натрупване на течност (трансудат или ексудат) в интерстициалното пространство и алвеолите на белия дроб, което води до тежки нарушения в газообмена.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза и класификация на белодробния оток</h2><p>Белодробният оток се класифицира в три основни групи според водещия патогенетичен механизъм:</p><h3>Хемодинамичен оток</h3><p>Този вид оток се дължи на физични промени в наляганията вътре в съдовете, без първоначално увреждане на самата съдна стена.</p><ul><li><strong>Увеличено хидростатично налягане:</strong> Кръвта се застоява в белодробните вени и капиляри. Повишеното налягане буквално „изстисква“ течната част на кръвта в алвеолите.</li><ul><li><em>Причини:</em> <strong>Левостранна сърдечна недостатъчност</strong> (най-честа), митрална стеноза, обемно натоварване на кръвообращението.</li></ul><li><strong>Намалено онкотично налягане:</strong> Когато в кръвта липсват белтъци (албумини), тя не може да задържа течността вътре в съда и тя излиза в тъканите.</li><ul><li><em>Причини:</em> Нефротичен синдром, чернодробна цироза, гладуване.</li></ul><li><strong>Обструкция на лимфатиците:</strong> Рядка причина, при която лимфният дренаж, който нормално „почиства“ интерстициума, е блокиран.</li></ul><h3>Оток поради увреждане на микросъдовете (Алвеоларно увреждане)</h3><p>Тук механизмът е <strong>директна деструкция на микроциркулацията</strong>. Мембраната между капиляра и алвеолата се разкъсва или става силно пропусклива.</p><ul><li><strong>Инфекциозни агенти:</strong> Бактериални пневмонии, септицемия.</li><li><strong>Инхалаторни дразнители:</strong> Вдишване на дим, токсични газове, чист кислород (кислородна токсичност).</li><li><strong>Аспирация:</strong> Навлизане на стомашно съдържимо (киселина) или течности (удавяне).</li><li><strong>Лекарства и токсини:</strong> Химиотерапия (напр. Блеомицин), тежки травми, радиация.</li></ul><h3>Некардиогенен белодробен оток (Системен/Неврологичен)</h3><p>В тази категория попадат случаите, при които отокът е следствие от системни заболявания на други органи или на нервната система, без директно сърдечно увреждане.</p><ul><li><strong>Болести на дихателната система</strong>: респираторен дистрес синдром, астма, емфизем, пневмония.</li><li><strong>Неврологичен оток:</strong> Възниква при тежки травми на централната нервна система (ЦНС) или мозъчни кръвоизливи.</li><li><strong>Болести на пикочно-половата система:</strong> Остър гломерулонефрит, уремия (задръжка на токсини).</li><li><strong>Заболявания на други органи:</strong> Остър панкреатит.</li><li><strong>Други системни състояния:</strong> Шок, тежки алергични реакции, нежелани реакции при кръвопреливане.</li><li><strong>Болести на нервно-мускулния апарат:</strong> Миастения гравис, синдром на Гилен-Баре, мускулна дистрофия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Морфологична характеристика</h2><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776260622937-image.png &quot;width=100%&quot;)\" id=\"note-1776260624977-68\">Макроскопски белези</span></h3><ul><li>Белите дробове стават тежки, обемът им е увеличен, а плътността – повишена.</li><li>Консистенцията е <strong>тестява</strong>, а еластичността е значително намалена. При натиск с пръст остава трайна ямка.</li><li>От срезната повърхност изтича обилно количество <strong>кръвениста или розова пенеста течност</strong> (наличието на пяна се дължи на смесването на оточната течност с въздуха в алвеолите и действието на сърфактанта).</li></ul><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776260613434-image.png &quot;width=100%&quot;)\" id=\"note-1776260615659-67\">Микроскопски белези</span></h3><ul><li>Наблюдава се разрехавяване и разединяване на структурите (интерстициален оток).</li><li>Колагенните и еластичните влакна са разнищени и разкъсани, като губят типичните си оцветителни свойства.</li><li>Наблюдава се вакуолизация на клетките и натрупване на течност в околоклетъчните пространства.</li><li>Налице е дилатация на лимфните съдове и увеличаване на околосъдовите пространства.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Изход и значение</h2><h3>Изход</h3><ul><li><strong>Благоприятен:</strong> При отстраняване на причината (напр. овладяване на сърдечната недостатъчност), трансудатът се резорбира и органът възстановява структурата и функцията си.</li><li><strong>Хроничен оток:</strong> Води до атрофия и дистрофия на паренхима, а интерстициумът претърпява <strong>фиброза и склероза</strong> (т.нар. „кафява индурация“ на белия дроб при хроничен застой).</li></ul><h3>Значение</h3><ul><li>Причинява остра дихателна недостатъчност.</li><li>Отокът може да причини тежки функционални нарушения в жизненоважни органи (мозък, бял дроб) и летален изход.</li><li>Наличието на оточна течност в алвеолите е отлична среда за развитие на бактерии.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 18. Доброкачествени и злокачествени тумори на белите дробове.</h1><p>Пример за доброкачествен тумор - <strong><span class=\"editor-note\" data-note=\"# Хамартом (Hamartoma pulmonis)\nХамартомът не е „истински“ неопластичен процес в смисъла на злокачествен рак, а по-скоро **малформация (тумороподобно образувание)**, съставена от нормални за даден орган тъкани, които обаче са подредени в хаотична структура.\n* **Характеристика:** Това е най-честият доброкачествен тумор на белия дроб. Той се развива бавно и обикновено е разположен в периферията на белодробния паренхим.\n* **Микроскопски състав:** Изграден е от смес от различни мезенхимни елементи. Най-често се наблюдават: * **Хрущялна тъкан** (типичен белег). * **Съединителна тъкан** (фиброзна). * **Мастна тъкан** (липоцити). * **Бронхиален епител** (понякога образуващ цепнативидни пространства).\n* **Макроскопски вид:** Обикновено представлява добре отграничен, плътен възел с лобулирана (нагъната) повърхност. На среза често изглежда сиво-бял, поради наличието на хрущялни елементи.\n* **Клинично значение:** * В повечето случаи хамартомът е безсимптомен и се открива случайно при рентгеново изследване като „периферна нодуларна сянка“. * Важно е да се разграничи от злокачествен тумор чрез образна диагностика (често се виждат характерни калцификати тип „пуканка“). * Поради доброкачествения си характер, не метастазира и расте изключително бавно.\" id=\"note-1776343955971-1\">хамартом</span></strong>.</p><blockquote>Огромни педали ако искат доброкачествени тумори примери и обяснения :)</blockquote><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Рак на белия дроб (Carcinoma pulmonum)</h2><h3>Честота и разпространение</h3><p>Този тумор съставлява <strong>90-95%</strong> от всички новообразувания на органа, като засяга предимно хора между 50 и 70 години. Поради масовото тютюнопушене съотношението мъже:жени е спаднало значително (вече е <strong>2:1</strong>), а смъртността при жените вече надвишава тази от рак на гърдата. Белодробният карцином се отличава с изключителна агресивност и лоша прогноза.</p><h3>Етиология:</h3><ul><li><p><strong>Тютюнопушене</strong>: Водещ фактор (80% от болните). Рискът е пропорционален на броя изпушени цигари.</p><br></li><li><p><strong>Канцерогени</strong>: Замърсен въздух (бензпирен, никел, берилий, азбест) и радиация (уранови мини).</p><br></li></ul><h3>Морфология:</h3><p>По произход туморът е най-често <strong>бронхогенен</strong> (от покривния или жлезния епител). В редки случаи (1-2%) е пневмогенен. Може да възникне около цикатрикси от стари инфаркти или туберкулоза, но често фиброзата е просто вторична реакция към самия тумор. Туморът се стадира с <strong><span class=\"editor-note\" data-note=\"# **I. TNM Класификация (Определения)**\n| Категория | Описание |\n| :--- | :--- |\n| **Tis** | **Carcinoma in situ** (предклиничен стадий) |\n| **T1** | Тумор **≤ 3 cm**, без засягане на плеврата или главния бронх (T1a: &lt;2cm; T1b: 2-3cm) |\n| **T2** | Тумор **3-7 cm** или засягане на висцералната плевра, лобарна ателектаза или главен бронх (на ≥2cm от карината) |\n| **T3** | Тумор **&gt; 7 cm** или инвазия в: гръдна стена, диафрагма, перикард, главен бронх (&lt;2cm от карината), отделни възли в същия лоб |\n| **T4** | Инвазия в: медиастинум, сърце, големи съдове, трахея, хранопровод, прешлени или отделни възли в различен лоб на същия дроб |\n| **N0** | Без метастази в регионалните лимфни възли |\n| **N1** | Метастази в ипсилатералните (от същата страна) перибронхиални или хилусни възли |\n| **N2** | Метастази в ипсилатералните медиастинални или субкаринални възли |\n| **N3** | Метастази в контралатерални (от срещуположната страна) медиастинални/хилусни или надключични възли |\n| **M0** | Без далечни метастази |\n| **M1** | Наличие на далечни метастази (M1a: в другия дроб или плеврален излив; M1b: далечни органи) |\n---\n# **II. Групиране по стадии (Stage Grouping)**\nТази таблица показва как комбинацията от T, N и M определя крайния клиничен стадий:\n| Стадий | T (Тумор) | N (Възли) | M (Метастази) |\n| :--- | :--- | :--- | :--- |\n| **Стадий IA** | T1a, T1b | N0 | M0 |\n| **Стадий IB** | T2a | N0 | M0 |\n| **Стадий IIA** | T2b **ИЛИ** T1/T2 | N0 **ИЛИ** N1 | M0 |\n| **Стадий IIB** | T2b **ИЛИ** T3 | N1 **ИЛИ** N0 | M0 |\n| **Стадий IIIA** | T1-T3 **ИЛИ** T4 | N2 **ИЛИ** N0-N1 | M0 |\n| **Стадий IIIB** | Всеки T **ИЛИ** T4 | N3 **ИЛИ** N2-N3 | M0 |\n| **Стадий IV** | Всеки T | Всеки N | **M1a, M1b** |\n---\n**Накратко за запомняне:**\n* **Стадий I:** Локализиран тумор без лимфни възли.\n* **Стадий II:** Туморът расте или засяга най-близките лимфни възли (N1).\n* **Стадий III:** Ангажиране на медиастинални възли (N2/N3) или инвазия в критични структури (T4).\n* **Стадий IV:** Наличие на далечни метастази (M1) – най-тежката прогноза.\" id=\"note-1776343839810-0\">TNM класификация</span></strong>.</p><h3>Разпространение и метастазиране</h3><p>Туморът инфилтрира паренхима, а в медиастинума може да притисне трахеята, хранопровода и големите съдове.</p><ul><li><strong>Лимфогенен път:</strong> Обхваща бронхо-пулмонални, паратрахеални и шийни възли. Предизвиква карциномна лимфангиоза в белия дроб и карциноза на плеврата и перикарда.</li><li><strong>Хематогенен път:</strong> Характерни са метастази в <strong>надбъбреците (над 50%)</strong>, черния дроб, мозъка и костите.</li></ul><h3>Хистологични закономерности</h3><p>Начинът на разпространение зависи от вида на тумора:</p><ul><li>Недиференцираният дребноклетъчен рак е най-агресивен с ранни метастази.</li><li>Плоскоклетъчният рак се разширява бързо локално, но метастазира по-късно.</li><li>Аденокарциномите растат по-бавно и периферните им форми често са свързани с цикатриски (<strong>scar-carcinoma</strong>).</li><li>Бронхоалвеоларният вариант не тръгва от големите бронхи и рядко дава метастази (едва в 45% от случаите).</li></ul><h3>Клинична картина</h3><p>Заболяването често е безсимптомно в началото. Първите признаци включват:</p><ul><li>Прогресивна (<strong>диспнея</strong>&nbsp;и упорита кашлица.</li><li>Гръдни болки и <strong>хемоптиза</strong>.</li><li>В 10% от случаите – <strong>синдром на горната празна вена</strong>.</li><li><strong>Паранеопластичен синдром</strong> (при дребноклетъчния рак) с продукция на хормони като ACTH.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Морфологични форми според локализацията</h3><p>Според мястото на възникване и начина на растеж различаваме две основни клинико-анатомични форми:</p><h4><strong>Централен (крайхилусен) карцином</strong></h4><p>Обхваща около <strong>3/4 от случаите</strong> и произлиза от големите бронхи (I, II и III ред).</p><ul><li><strong>Начин на растеж:</strong> Може да бъде <strong>екзофитен</strong> (навътре в лумена на бронха) или <strong>ендофитен</strong> (инфилтрира стената и околната тъкан).</li><li><strong>Макроскопски белези:</strong> Туморът предизвиква задебеляване на бронхиалната стена, което води до стеноза или пълно запушване на лумена. Често оформя масивен, сивкаво-жълтеникав възел със зърниста повърхност, некрози и кръвоизливи. Понякога се разпространява ветрилообразно по хода на бронхите.</li></ul><h4><strong>Периферен карцином</strong></h4><p>Среща се в около <strong>25% от случаите</strong> и се развива от малките дистални бронхи.</p><ul><li><strong>Макроскопски белези:</strong> Установява се като възел с различна големина в паренхима. Понякога е толкова малък, че се открива чак след появата на далечни метастази.</li><li><strong>Тумор на Панкоаст (Pancoast):</strong> Специфична локализация във върха на белия дроб. Прораства в плеврата, гръдната стена и нервните сплитове. Клинично се проявява със <strong>синдром на Claude Bernard-Horner</strong> (миоза, птоза, енофталм) и липса на изпотяване (анхидроза) от страната на лезията.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Макроскопски форми:</h3><p>Основните макроскопски форми на карцинома на белия дроб включват:</p><ul><li><strong>Масивен прихилусен възел</strong>: засяга големите бронхи.</li><li><strong>Голям периферен възел</strong>: локализиран в интермедиерната или периферната зона.</li><li><strong>Малък периферен рак </strong>на бронха: разположен в периферната част на бронха. Често се открива трудно и се представя директно чрез метастазите си.</li><li><strong>Кортико</strong>-<strong>плеврална </strong>(<strong>ветрилообразна</strong>) <strong>форма</strong>.</li><li><strong>Пневмонична форма</strong>.</li><li><strong>Тумор на Панкоаст</strong>.</li><li><strong>Мултифокален </strong>(<strong>милиарен</strong>) <strong>карцином</strong>: изисква диференциална диагноза с туберкулоза.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Хистологични варианти на белодробния карцином</h3><p>Разделят се на:</p><ul><li><strong>Дребноклетъчен карцином</strong></li><li><strong>Недребноклетъчен карцином</strong>: аденокарцином, плоскоклетъчен карцином, едроклетъчен карцином.</li></ul><h4>1. Плоскоклетъчен (сквамозен) карцином</h4><p>Това е най-честият вариант (35-50%), типичен за <strong>централните </strong>локализации при мъже, дългогодишни пушачи. Развива се основно върху базата на плоскоклетъчна метаплазия на бронхиалния епител.</p><ul><li><strong>Микроскопия:</strong> Наблюдават се гнезда от полигонални или окръглени клетки, понякога със запазени междуклетъчни мостчета. </li><li><strong>Диференциация:</strong> Определя се в три степени (високо-, умерено- и нискодиференциран) според изразеността на клетъчния полиморфизъм и наличието на кератинообразуване — т.нар. <strong>ракови перли</strong>.</li></ul><h4>2. Аденокарцином</h4><p>Заема 15-35% от случаите и обикновено има <strong>периферна </strong>локализация. Среща се с еднаква честота при мъже и жени, като произходът му е свързан с бронхиалните жлези.</p><ul><li><strong>Микроскопия:</strong> Формира жлезисти структури с различна степен на зрялост. </li><li><strong>Бронхиолоалвеоларен карцином:</strong> Важен подвариант, произхождащ от Клара-клетки или пневмоцити тип II. Характеризира се с разрастване на високи атипични цилиндрични клетки, съдържащи муцин. Те покриват алвеоларните стени и ходове, като <strong>запазват архитектониката</strong> на белия дроб и образуват папиларни структури към пространствата, изпълнени със слуз. Макроскопски на срез изглежда сивкав и слузест, наподобяващ пневмония - \"<strong>пневмонична форма</strong>\".</li></ul><h4>3. Дребноклетъчен недиференциран карцином (Small cell)</h4><p>Най-агресивният хистологичен вариант (20-25%), обикновено разположен <strong>централно</strong>. </p><ul><li><strong>Микроскопия:</strong> Състои се от малки клетки с оскъдна цитоплазма. Ядрата са хиперхромни и могат да бъдат кръгли (лимфоцитоподобни) или овални — тип <strong>„овесени зърна“</strong>. Често дава паранеопластични синдроми поради хормонална продукция (ACTH, антидиуретичен хормон).</li></ul><h4>4. Едроклетъчен недиференциран (гигантоклетъчен) карцином</h4><p>Среща се сравнително рядко (10-15%) и е обикновено разположен <strong>периферно</strong>. Изграден е от големи полигонални клетки с подчертан анапластичен характер и везикуларни ядра. Често се срещат гигантски клетки.</p><h4>5. Редки и смесени форми</h4><ul><li><strong>Аденосквамозен карцином:</strong> Комбинира елементи на аденокарцином и плоскоклетъчен рак, като и двата компонента са малигнени.</li><li><strong>Тумори от слюнчено-жлезен произход:</strong> Включват мукоепидермоидни и аденокистични карциноми. Те се отличават с бавен растеж и рядко метастазират.</li></ul><h4>6. <strong>Невроендокринни тумори (Карциноиди)</strong></h4><p>Произлизат от дифузната невроендокринна система и се отличават с по-бавна еволюция в сравнение с карциномите.</p><ul><li><strong>Макроскопия:</strong> Проявяват се като полиповидни разраствания по бронхиалната лигавица.</li><li><strong>Микроскопия:</strong> Характеризират се с гнезда от еднообразни клетки с кръгли или овални ядра, разделени от фини съединителнотъканни прегради. Цитоплазмата им е зърниста и съдържа аргирофилни гранули.</li><li><strong>Диагностика:</strong> Невроендокринната им природа се доказва имунохистохимично (маркери: синаптофизин, хромогранин А, невронспецифична енолаза) или чрез електронна микроскопия (наличие на везикули с плътно ядро – <em>dense core vesicles</em>).</li><li><strong>Атипичен карциноид:</strong> По-агресивен вариант с изразен клетъчен атипизъм, висок митотичен индекс и склонност към метастазиране.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Усложнения на белодробния карцином:</h3><ul><li><strong>Механично увреждане</strong>: Парциалната обструкция води до фокален <strong>емфизем</strong>, а пълната до <strong>ателектаза</strong>&nbsp;на съответния участък.</li><li><strong>Синдром на горната празна вена:</strong> Причинява се от притискане на съда от лимфогенни метастази в медиастинума.</li><li><strong>Възпалителни процеси:</strong> Около карцинома често се развива т.нар. <strong>мантелна пневмония</strong>. Може да се развият белодробни <strong>абсцеси</strong>.</li><li><strong>Кръвоизливи:</strong> Некрозата на туморната тъкан може да обхване кръвоносен съд, което води до масивни и често смъртоносни кръвоизливи.</li><li><strong>Ятрогенни усложнения:</strong> В съвременната практика зачестяват токсичните ефекти и имуносупресията, предизвикани от химиотерапията.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Метастатични тумори на белия дроб</h3><p>Белите дробове са често място за метастази на тумори с епителен и мезенхимен произход от различни първични огнища.</p><p><strong>1. Първична локализация на източниците:</strong></p><p>Обикновено метастази в белия дроб дават:</p><ul><li>Бъбречен карцином и герминативноклетъчни тумори (хориокарцином, ембрионален карцином).</li><li>Меланоми и рак на гърдата.</li><li>Карциноми на хранопровода и други нива на гастроинтестиналния път.</li><li>Рак на женските гениталии и остеосарком.</li></ul><p><strong>2. Начин на разпространение:</strong></p><p>Метастазите се развиват чрез три основни пътя:</p><ul><li>Хематогенна разсейка.</li><li>Лимфогенна разсейка.</li><li>Директно разпространение от съседни тумори на гръдната стена или медиастинума.</li></ul><p><strong>3. Морфологична изява:</strong></p><p>Метастатичните огнища могат да се представят като:</p><ul><li>Единични възли.</li><li>Множествени възли.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 19. Възпалителни и туморни процеси на плеврата. Морфологична характеристика.</h1><p>Патологичните процеси в плеврата в преобладаващия брой случаи са <strong style=\"color: rgb(31, 41, 55)\">вторични</strong>. Те са свързани с изменения в белите дробове или други органи (сърце, бъбреци). Понякога плевралното засягане може да доминира в клиничната картина и да определи изхода на заболяването (например емпием или карциноза).</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Плеврит (Pleuritis)</h2><p>Плевритът е едно от най-честите възпалителни заболявания, което почти никога не протича самостоятелно.</p><p><strong>Етиология:</strong></p><ul><li><strong>Инфекциозен:</strong> Предизвикан от бактерии (туберкулозни, стафилококи, стрептококи), гъбички или паразити.</li><li><strong>Асептичен:</strong> Развива се при белодробен инфаркт, уремия, както и при първични или метастатични тумори.</li></ul><h4>Морфологични форми според ексудата</h4><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776608081097-image.png &quot;width=100%&quot;)\" id=\"note-1776252559042-61\">Серозен, серо-фибринозен и фибринозен плеврит</span>:</strong></li><ul><li>Често се разглеждат като фази на един процес (при туберкулоза, пневмония, уремия).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776252502022-image.png &quot;width=100%&quot;)\" id=\"note-1776252503804-60\">Макроскопски</span>:</strong> Плеврата изглежда като „надъхано стъкло“ и се покрива с нежен фибринозен налеп. При по-обилен ексудат повърхността става неравна и набраздена (дебелина до 1-2 cm).</li><li><strong>Изход:</strong> Ексудатът може да се резорбира или да се организира, което води до сраствания (<strong>pleuritis chronica fibrosa s. adhaesiva</strong>).</li></ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776252589373-image.png &quot;width=100%&quot;)\" id=\"note-1776252591626-62\">Гноен плеврит (Empyema pleurae)</span>:</strong></li><ul><li>Тежко състояние, развиващо се по съседство (от пневмония или абсцес) или по кръвен път.</li><li><strong>Характеристика:</strong> В кухината се събира гъста жълто-зеленикава гной (понякога до 1000 ml).</li><li><strong>Изход:</strong> Резорбцията е трудна. Организацията води до образуване на плътна фиброзна тъкан, наречена <strong>плеврална шварта</strong>, в която често се отлага калций.</li></ul><li><strong>Хеморагичен плеврит:</strong></li><ul><li>Наблюдава се при туморно ангажиране, хеморагични диатези или рикетсиози. Трябва да се различава от хемоторакс (кръвоизлив в кухината, напр. при руптура на аортна аневризма).</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Плеврални изливи (Невъзпалителни)</h3><p>При нормални условия в плевралната кухина има около 15 ml бистра течност. При патология се събират различни по вид изливи, като може да се използват и <strong><span class=\"editor-note\" data-note=\"# Критерии на Light (Light's Criteria)\nЗа да се класифицира един излив като **ексудат**, е необходимо да бъде изпълнен поне **един** от следните три критерия:\n1. **Протеин (Плевра / Серум):** Съотношението на протеина в плевралната течност към протеина в серума е по-голямо или равно на **0.5**.\n2. **LDH (Плевра / Серум):** Съотношението на лактат дехидрогеназата (LDH) в плевралната течност към тази в серума е по-голямо или равно на **0.6**.\n3. **LDH в плеврална течност:** Стойността на LDH в плевралната течност е по-голяма от **2/3 от горната граница на нормата** за серумен LDH.\nАко нито един от тези критерии не е изпълнен, изливът се определя като **трансудат**.\n---\n# Основни причини за изливите\n* **Трансудат (често поради системни фактори):** * Сърдечна недостатъчност. * Цироза. * Нефротичен синдром. * Белодробна емболия (може да бъде и трансудат). * Ателектаза.\n* **Ексудат (често поради локални фактори или възпаление):** * Малигнени заболявания. * Бактериална или вирусна пневмония. * Туберкулоза. * Панкреатит. * Руптура на хранопровода. * Колагенози (съдови съединителнотъканни заболявания). * Хилоторакс или Хемоторакс.\" id=\"note-1776255887108-64\">критериите на Light</span></strong>:</p><ul><li><strong>Хидроторакс (Hydrothorax):</strong> Набиране на серозна течност (бистра, сламеножълта).</li><li><strong>Хилоторакс (Chylothorax):</strong> Набиране на лимфа (млечнобяла течност, богата на мазнини).</li><li><strong>Пневмоторакс (Pneumothorax):</strong> Събиране на въздух в кухината.</li><ul><li><strong>Спонтанен:</strong> Често при емфизем, астма или туберкулоза.</li><li><strong>Травматичен:</strong> При нараняване на гръдната стена или белия дроб.</li><li><strong>Терапевтичен:</strong> Използван в миналото за колабиране на белия дроб при туберкулоза.</li><li><strong>Вентилен (клапен) пневмоторакс:</strong> Въздухът навлиза при вдишване, но не може да излезе при издишване поради „клапа“ от фибринозен ексудат. Това е критично състояние.</li></ul></ul><h3>Механизми за възникване на плеврални изливи</h3><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Причина (заболяване)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Механизъм на възникване</span></strong></td></tr><tr><td><strong>Сърдечна недостатъчност</strong></td><td>Увеличено хидростатично налягане</td></tr><tr><td><strong>Пневмонии</strong></td><td>Увеличена съдова пропускливост</td></tr><tr><td><strong>Нефротичен синдром</strong></td><td>Намалено онкотично налягане</td></tr><tr><td><strong>Ателектаза</strong></td><td>Увеличено негативно интраплеврално налягане</td></tr><tr><td><strong>Метастази в лимфни възли</strong></td><td>Затруднен лимфен дренаж</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Тумори на плеврата</h2><p>Туморите на плеврата се делят на две основни групи: вторични (метастатични), които са по-чести, и първични.</p><h3>Карциноза на плеврата</h3><p>Това е състояние на дисеминирано разпространение на метастатичен тумор по серозните повърхности.</p><ul><li><strong>Източници:</strong> Най-често произхожда от <strong>белодробен карцином</strong>, но може да бъде резултат и от отдалечени метастази (по хематогенен път) от карцином на яйчник, гърда или стомашно-чревния тракт.</li><li><strong>Макроскопска картина:</strong> Плеврата е осеяна с множество дребни, сивкави и леко изпъкнали възелчета. Често се придружава от значително количество серозен или <strong>серозно-хеморагичен ексудат</strong>.</li><li><strong>Диагностика:</strong> Цитологичното изследване на плевралния излив е критично важно, тъй като позволява откриването на комплекси от карциномни клетки и идентифициране на техния първичен произход.</li></ul><h3>Мезотелиом</h3><p>Това е най-честият първичен тумор на плеврата, произлизащ от мезотелните клетки.</p><h4>Дифузен малигнен мезотелиом</h4><ul><li><strong>Етиология:</strong> Над 90% от случаите са свързани с експозиция на <strong>азбест</strong>. Най-канцерогенни са влакната тип крокидолит. Допуска се роля и на вируса SV40, както и на терапевтичната радиация.</li><li><strong>Макроскопска картина:</strong> Започва като малки сивкаво-розови нодули по париеталната плевра. В напреднал стадий те се сливат, обхващат цялата плевра и водят до срастване на листовете ѝ, което предизвиква ателектаза на белия дроб.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-15/text-editor-images/2026/04/1776252697002-image.png &quot;width=100%&quot;)\" id=\"note-1776252700630-63\">Микроскопски варианти</span>:</strong></li><ol><li><strong>Епителоиден:</strong> Големи клетки с еозинофилна цитоплазма, формиращи жлезоподобни структури. Имитира карцином, затова се доказва чрез имунохистохимия (за доказване на <strong>калретинин</strong>, <strong>mesothel-cell антиген</strong>). Има по-добра прогноза.</li><li><strong>Саркоматоиден:</strong> Вретеновидни клетки, подредени в снопчета (прилича на фибросарком).</li><li><strong>Дезмопластичен:</strong> Характеризира се с плътна колагенова строма и много агресивно поведение.</li><li><strong>Бифазен:</strong> Съдържа смес от епителоидни и саркоматоидни компоненти.</li></ol><li><strong>Разпространение:</strong> Туморът инфилтрира гръдната стена, диафрагмата (може да премине в перитонеума) и подлежащия бял дроб. Дава хематогенни метастази в черен дроб, кости и надбъбречни жлези.</li></ul><h4>Локализиран малигнен мезотелиом</h4><p>Различава се от дифузния по своя ограничен нодуларен характер. Трябва да се разграничава от други доброкачествени образувания като:</p><ul><li>Солитарен фиброзен тумор.</li><li>Добре диференциран папиларен мезотелиом.</li><li>Аденоматоиден тумор (винаги бенигнен).</li></ul><br><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
